// Package cognitive provides autonomous background processes for memory consolidation,
// contradiction detection, and meta-knowledge generation (Reflection Engine).
package cognitive

import (
	"encoding/json"
	"fmt"
	"log/slog"
	"math"
	"slices"
	"sort"
	"strings"
	"sync"
	"sync/atomic"
	"time"

	"github.com/sanonone/kektordb/pkg/core"
	"github.com/sanonone/kektordb/pkg/core/hnsw"
	"github.com/sanonone/kektordb/pkg/engine"
	"github.com/sanonone/kektordb/pkg/llm"
)

// ReflectionType categorizes the insights generated by the Gardener.
type ReflectionType string

const (
	TypeConsolidation ReflectionType = "consolidation" // Merged redundant memories
	TypeContradiction ReflectionType = "contradiction" // Detected conflicting facts
	TypeImportance    ReflectionType = "importance"    // Importance shift
	TypeCoreFact      ReflectionType = "core_fact"     // Extracted immutable user facts
)

// Reflection defines the schema for a meta-memory node.
// These will be stored in the DB with kind="reflection" and linked to original memories.
type Reflection struct {
	Type        ReflectionType `json:"type"`
	Content     string         `json:"content"`
	Confidence  float64        `json:"confidence"`
	Status      string         `json:"status"`       // e.g., "resolved", "unresolved"
	DerivedFrom []string       `json:"derived_from"` // Original memory IDs
}

// Config holds the scheduling and AI settings for the cognitive engine.
type Config struct {
	Enabled             bool
	Interval            time.Duration // Default polling interval
	Mode                string        // "basic", "advanced", or "meta"
	TargetIndexes       []string      // ["*"] for all, or ["mcp_memory"]
	AdaptiveThreshold   int64         // Write count to trigger early think (default: 50)
	AdaptiveMinInterval time.Duration // Min time between forced thinks (default: 30s)

	// Auto-resolve settings
	AutoResolveEnabled  bool    // Enable auto-resolution of whitelisted reflection types
	AutoResolveLinks    bool    // Auto-create suggested graph links (from knowledge gaps)
	AutoResolveLinksMin float64 // Min confidence to auto-create a link (default: 0.90)
	AutoResolveContra   bool    // Auto-resolve minor contradictions (action_required=false)

	// Memory layer configuration
	MemoryConfig hnsw.MemoryConfig

	// User profiling
	EnableUserProfiling    bool // Enable user personality profiling
	ProfileUpdateThreshold int  // Number of user_interaction memories before profile update

	// Core Fact Extraction (RFC 001)
	EnableCoreFactExtraction bool    // Enable automatic extraction of immutable facts
	CoreFactMinConfidence    float64 // Minimum confidence threshold for extracted facts (default: 0.85)

	// Epistemic Resolution (Fase 3)
	EpistemicResolutionEnabled   bool    // Enable epistemic auto-resolution using VBeliefState
	EpistemicMaxPerCycle         int     // Max reflections to process per cycle (default: 3)
	EpistemicConfidenceThreshold float64 // Min confidence to trigger resolution (default: 0.40)
}

// Gardener is the autonomous background worker that analyzes the database graph
// to consolidate memories and generate reflections.
type Gardener struct {
	eng            *engine.Engine
	llm            llm.Client // LLM client for synthesis and reasoning
	cfg            Config
	stopCh         chan struct{}
	eventCh        chan engine.Event // Subscribed to engine event bus
	scanCursors    map[string]uint32
	cursorsMu      sync.RWMutex // Protects scanCursors from concurrent access
	writeCounter   atomic.Int64 // Write events since last think (atomic for thread-safe access)
	lastThinkTime  time.Time    // When the last think() completed
	lastThinkMu    sync.RWMutex // Protects lastThinkTime from concurrent access
	newReflections []string     // Reflection IDs created in current think() cycle
	reflectionsMu  sync.Mutex   // Protects newReflections from concurrent access

	// User profiling
	unassimilatedInteractions map[string]int // user_id -> count of new interactions
	profileMutex              sync.RWMutex
}

// getCursor returns the current cursor for the given index with read lock.
func (g *Gardener) getCursor(indexName string) uint32 {
	g.cursorsMu.RLock()
	defer g.cursorsMu.RUnlock()
	return g.scanCursors[indexName]
}

// setCursor updates the cursor for the given index with write lock.
func (g *Gardener) setCursor(indexName string, cursor uint32) {
	g.cursorsMu.Lock()
	defer g.cursorsMu.Unlock()
	g.scanCursors[indexName] = cursor
}

// getLastThinkTime returns the last think time with read lock.
func (g *Gardener) getLastThinkTime() time.Time {
	g.lastThinkMu.RLock()
	defer g.lastThinkMu.RUnlock()
	return g.lastThinkTime
}

// setLastThinkTime updates the last think time with write lock.
func (g *Gardener) setLastThinkTime(t time.Time) {
	g.lastThinkMu.Lock()
	defer g.lastThinkMu.Unlock()
	g.lastThinkTime = t
}

// filterNodesByLayer filters a list of node IDs to include only those with the specified memory layer.
func (g *Gardener) filterNodesByLayer(idx string, nodeIDs []string, layer string) []string {
	var filtered []string
	for _, id := range nodeIDs {
		meta, err := g.eng.VGet(idx, id)
		if err != nil {
			continue
		}
		nodeLayer := "episodic" // default
		if l, ok := meta.Metadata["memory_layer"].(string); ok && l != "" {
			nodeLayer = l
		}
		if nodeLayer == layer {
			filtered = append(filtered, id)
		}
	}
	return filtered
}

// filterNodesByLayers filters a list of node IDs to include only those with layers in the specified set.
func (g *Gardener) filterNodesByLayers(idx string, nodeIDs []string, layers []string) []string {
	layerSet := make(map[string]bool)
	for _, l := range layers {
		layerSet[l] = true
	}

	var filtered []string
	for _, id := range nodeIDs {
		meta, err := g.eng.VGet(idx, id)
		if err != nil {
			continue
		}
		nodeLayer := "episodic" // default
		if l, ok := meta.Metadata["memory_layer"].(string); ok && l != "" {
			nodeLayer = l
		}
		if layerSet[nodeLayer] {
			filtered = append(filtered, id)
		}
	}
	return filtered
}

// getAllNodes retrieves all node IDs in an index, optionally filtered by layer.
func (g *Gardener) getAllNodes(idx string, layerFilter string) []string {
	// Use VFilter to get all nodes, optionally with layer filter
	var filter string
	if layerFilter != "" {
		filter = fmt.Sprintf("memory_layer='%s'", layerFilter)
	}

	ids, err := g.eng.VFilter(idx, filter, 0) // 0 = no limit
	if err != nil {
		return nil
	}
	return ids
}

type llmContradictionResponse struct {
	Contradiction       bool   `json:"contradiction"`
	Reason              string `json:"reason"`
	SuggestedResolution string `json:"suggested_resolution"`
	ActionRequired      bool   `json:"action_required"`
}

type llmPreferenceResponse struct {
	PreferencesDiscovered map[string]string `json:"preferences_discovered"`
	Recommendation        string            `json:"recommendation"`
}

type llmFailurePatternResponse struct {
	Pattern        string `json:"pattern"`
	RootCause      string `json:"root_cause"`
	Recommendation string `json:"recommendation"`
	Severity       string `json:"severity"`
}

type llmEvolutionResponse struct {
	Timeline        string   `json:"timeline"`
	CompetencyLevel string   `json:"competency_level"`
	KnowledgeGaps   []string `json:"knowledge_gaps"`
	NextSteps       string   `json:"next_steps"`
}

// NewGardener initializes the cognitive engine.
func NewGardener(eng *engine.Engine, llmClient llm.Client, cfg Config) *Gardener {
	if cfg.Interval == 0 {
		cfg.Interval = 10 * time.Minute // Default: think every 10 minutes
	}
	if cfg.AdaptiveThreshold == 0 {
		cfg.AdaptiveThreshold = 50
	}
	if cfg.AdaptiveMinInterval == 0 {
		cfg.AdaptiveMinInterval = 30 * time.Second
	}
	if cfg.ProfileUpdateThreshold == 0 {
		cfg.ProfileUpdateThreshold = 20
	}
	if cfg.CoreFactMinConfidence == 0 {
		cfg.CoreFactMinConfidence = 0.85 // Default confidence threshold for core facts
	}

	eventCh := eng.EventBus.Subscribe(64)

	return &Gardener{
		eng:         eng,
		llm:         llmClient,
		cfg:         cfg,
		stopCh:      make(chan struct{}),
		eventCh:     eventCh,
		scanCursors: make(map[string]uint32),

		// User profiling
		unassimilatedInteractions: make(map[string]int),
	}
}

// Start launches the Gardener's background loop.
func (g *Gardener) Start() {
	if !g.cfg.Enabled {
		return
	}
	slog.Info("[Cognitive Engine] Gardener started. Sleep cycle initiated.", "interval", g.cfg.Interval)
	go g.loop()
}

// Stop gracefully halts the cognitive engine.
func (g *Gardener) Stop() {
	if !g.cfg.Enabled {
		return
	}
	close(g.stopCh)
	g.eng.EventBus.Unsubscribe(g.eventCh)
	slog.Info("[Cognitive Engine] Gardener stopped.")
}

func (g *Gardener) loop() {
	ticker := time.NewTicker(g.cfg.Interval)
	defer ticker.Stop()

	for {
		select {
		case <-g.stopCh:
			return
		case event, ok := <-g.eventCh:
			if !ok {
				return
			}
			g.onEvent(event)
		case <-ticker.C:
			g.writeCounter.Store(0)
			g.think()
			g.setLastThinkTime(time.Now())
		}
	}
}

// onEvent processes engine write events for adaptive scheduling and user profiling.
func (g *Gardener) onEvent(event engine.Event) {
	g.writeCounter.Add(1)

	// Adaptive trigger: wake up early if write rate exceeds threshold
	if g.writeCounter.Load() >= g.cfg.AdaptiveThreshold {
		if time.Since(g.getLastThinkTime()) > g.cfg.AdaptiveMinInterval {
			g.writeCounter.Store(0)
			go func() {
				g.think()
				g.setLastThinkTime(time.Now())
			}()
		}
	}

	// User profiling: track new user_interaction memories
	if g.cfg.EnableUserProfiling && event.Type == "vector.add" {
		g.trackUserInteraction(event)
	}
}

// trackUserInteraction increments the unassimilated counter for user profiling.
func (g *Gardener) trackUserInteraction(event engine.Event) {
	if event.IndexName == "" || event.ID == "" {
		return
	}

	data, err := g.eng.VGet(event.IndexName, event.ID)
	if err != nil {
		return
	}

	// Check if memory has user_id and tags include user_interaction
	userID, hasUserID := data.Metadata["user_id"].(string)
	if !hasUserID || userID == "" {
		return
	}

	tags, hasTags := data.Metadata["tags"].([]any)
	if !hasTags {
		return
	}

	hasUserInteraction := false
	for _, t := range tags {
		if tagStr, ok := t.(string); ok && tagStr == "user_interaction" {
			hasUserInteraction = true
			break
		}
	}

	if !hasUserInteraction {
		return
	}

	// Increment counter
	g.profileMutex.Lock()
	g.unassimilatedInteractions[userID]++
	count := g.unassimilatedInteractions[userID]
	g.profileMutex.Unlock()

	// If threshold reached, trigger profile update
	if count >= g.cfg.ProfileUpdateThreshold {
		go func() {
			g.UpdateUserProfile(event.IndexName, userID)
		}()
	}
}

// isIndexAllowed checks whether this index is in the Gardener's target list.
func (c *Config) isIndexAllowed(indexName string) bool {
	if len(c.TargetIndexes) == 0 {
		return false
	}
	for _, target := range c.TargetIndexes {
		if target == "*" || target == indexName {
			return true
		}
	}
	return false
}

// think is the main entry point for the "REM Sleep" phase of the database.
func (g *Gardener) think() {
	slog.Info("[Cognitive Engine] Gardener is waking up... scanning all active namespaces.")

	g.reflectionsMu.Lock()
	g.newReflections = nil // Reset tracking for this cycle
	g.reflectionsMu.Unlock()

	indexInfos, err := g.eng.DB.GetVectorIndexInfoAPI()
	if err != nil || len(indexInfos) == 0 {
		return
	}

	for _, info := range indexInfos {
		idx := info.Name

		// 1. Skip indexes not in the target list.
		if !g.cfg.isIndexAllowed(idx) {
			continue
		}

		// 2. Skip indexes with too few vectors to produce meaningful clusters.
		if info.VectorCount < 10 {
			continue
		}

		slog.Debug("[Cognitive Engine] Analyzing namespace", "index", idx, "mode", g.cfg.Mode)

		// =====================================================================
		// LAYER 1: BASIC (Fast, Math & Graph Only, NO LLM)
		// Always active when enabled. CPU cost: low.
		// =====================================================================

		// Memory-layer aware detection (operates on semantic + episodic, excludes procedural)
		g.detectKnowledgeGaps(idx)
		g.detectImportanceShifts(idx)
		g.detectSentimentShifts(idx, info.TextLanguage)
		g.detectCentralityShifts(idx)
		g.detectForgettingPatterns(idx)

		// Consolidation: Handle episodic -> semantic separately from general consolidation
		if g.cfg.MemoryConfig.Layers["episodic"].AutoSummarize {
			// Find clusters specifically in episodic layer
			episodicClusters := g.findRedundantClustersInLayer(idx, "episodic", g.cfg.MemoryConfig.Consolidation.SimilarityThreshold, 5)
			for _, cluster := range episodicClusters {
				g.consolidateEpisodicToSemantic(idx, cluster)
			}
		}

		// General consolidation for non-episodic memories (or all if episodic auto-summarize is off)
		clusters := g.findRedundantClusters(idx, 0.90, 5)
		for _, cluster := range clusters {
			g.consolidateCluster(idx, cluster) // LLM used if available, deterministic fallback otherwise.
		}

		// Advanced-only: contradiction detection (requires LLM).
		// Operates on semantic + episodic layers, excludes procedural.
		if g.llm != nil && (g.cfg.Mode == "advanced" || g.cfg.Mode == "meta") {
			g.detectContradictions(idx)
			g.detectUserPreferences(idx)
			g.detectRepeatedFailures(idx)
			g.detectKnowledgeEvolution(idx)

			// RFC 001: Core Fact Extraction
			if g.cfg.EnableCoreFactExtraction {
				g.detectCoreFacts(idx)
			}
		}

		// Meta-analysis: cross-detector confidence validation (meta mode only).
		g.reflectionsMu.Lock()
		newReflectionsCount := len(g.newReflections)
		g.reflectionsMu.Unlock()
		if g.cfg.Mode == "meta" && newReflectionsCount > 1 {
			g.detectCrossValidator(idx)
		}

		// Epistemic resolution: resolve volatile beliefs using VBeliefState
		if g.cfg.EpistemicResolutionEnabled {
			g.resolveVolatileBeliefs(idx)
		}
	}

	slog.Info("[Cognitive Engine] Sleep cycle completed. Graph optimized.")

}

// MemoryCluster represents a group of highly similar memories.
type MemoryCluster struct {
	CenterID  string
	MemberIDs []string
}

func (g *Gardener) findRedundantClusters(indexName string, similarityThreshold float64, minClusterSize int) []MemoryCluster {
	currentCursor := g.getCursor(indexName)

	ids, nextCursor, err := g.eng.VGetIDsByCursor(indexName, currentCursor, 500)
	if err != nil || len(ids) == 0 {
		return nil
	}
	g.setCursor(indexName, nextCursor)

	vectorDataList, err := g.eng.VGetMany(indexName, ids)
	if err != nil {
		return nil
	}

	var clusters []MemoryCluster
	clusteredSet := make(map[string]struct{})

	for _, vData := range vectorDataList {
		if _, alreadyClustered := clusteredSet[vData.ID]; alreadyClustered {
			continue
		}

		// Skip archived memories and meta-nodes (master/reflections).
		if archived, ok := vData.Metadata["_archived"].(bool); ok && archived {
			continue
		}
		if memType, ok := vData.Metadata["type"].(string); ok && (memType == "consolidated_memory" || memType == "reflection") {
			continue
		}

		results, err := g.eng.VSearchWithScores(indexName, vData.Vector, 10)
		if err != nil {
			continue
		}

		var currentCluster []string
		for _, res := range results {
			if res.Score >= similarityThreshold {
				if _, seen := clusteredSet[res.ID]; !seen {
					// Also skip archived or meta-type neighbors.
					neighborData, err := g.eng.VGet(indexName, res.ID)
					if err == nil {
						if arch, ok := neighborData.Metadata["_archived"].(bool); ok && arch {
							continue
						}
						if memType, ok := neighborData.Metadata["type"].(string); ok && (memType == "consolidated_memory" || memType == "reflection") {
							continue
						}

						currentCluster = append(currentCluster, res.ID)
						clusteredSet[res.ID] = struct{}{}
					}
				}
			}
		}

		if len(currentCluster) >= minClusterSize {
			clusters = append(clusters, MemoryCluster{
				CenterID:  vData.ID,
				MemberIDs: currentCluster,
			})
		}
	}

	return clusters
}

// findRedundantClustersInLayer finds clusters specifically within a single memory layer.
// This is used for layer-specific consolidation (e.g., episodic -> semantic).
func (g *Gardener) findRedundantClustersInLayer(indexName string, layer string, similarityThreshold float64, minClusterSize int) []MemoryCluster {
	// Use VFilter to get all nodes in this layer
	filter := fmt.Sprintf("memory_layer='%s'", layer)
	ids, err := g.eng.VFilter(indexName, filter, 1000)
	if err != nil || len(ids) == 0 {
		return nil
	}

	vectorDataList, err := g.eng.VGetMany(indexName, ids)
	if err != nil {
		return nil
	}

	var clusters []MemoryCluster
	clusteredSet := make(map[string]struct{})

	for _, vData := range vectorDataList {
		if _, alreadyClustered := clusteredSet[vData.ID]; alreadyClustered {
			continue
		}

		// Skip archived memories and meta-nodes
		if archived, ok := vData.Metadata["_archived"].(bool); ok && archived {
			continue
		}
		if memType, ok := vData.Metadata["type"].(string); ok && (memType == "consolidated_memory" || memType == "reflection" || memType == "semantic_memory") {
			continue
		}

		results, err := g.eng.VSearchWithScores(indexName, vData.Vector, 10)
		if err != nil {
			continue
		}

		var currentCluster []string
		for _, res := range results {
			if res.Score >= similarityThreshold {
				if _, seen := clusteredSet[res.ID]; !seen {
					neighborData, err := g.eng.VGet(indexName, res.ID)
					if err != nil {
						continue
					}
					// Verify neighbor is in the same layer
					neighborLayer := "episodic"
					if l, ok := neighborData.Metadata["memory_layer"].(string); ok && l != "" {
						neighborLayer = l
					}
					if neighborLayer != layer {
						continue
					}
					// Skip archived or meta-type neighbors
					if arch, ok := neighborData.Metadata["_archived"].(bool); ok && arch {
						continue
					}
					if memType, ok := neighborData.Metadata["type"].(string); ok && (memType == "consolidated_memory" || memType == "reflection" || memType == "semantic_memory") {
						continue
					}

					currentCluster = append(currentCluster, res.ID)
					clusteredSet[res.ID] = struct{}{}
				}
			}
		}

		if len(currentCluster) >= minClusterSize {
			clusters = append(clusters, MemoryCluster{
				CenterID:  vData.ID,
				MemberIDs: currentCluster,
			})
		}
	}

	return clusters
}

// consolidateCluster sends redundant memories to the LLM for synthesis, creates a Master Memory,
// and archives the original memories by linking them via the graph.
func (g *Gardener) consolidateCluster(indexName string, cluster MemoryCluster) {
	// 1. Fetch data for all memories in the cluster
	items, err := g.eng.VGetMany(indexName, cluster.MemberIDs)
	if err != nil || len(items) == 0 {
		return
	}

	// 2. Prepare text and compute the Average Vector (Zero-Cost Embedding!)
	var texts []string
	dim := len(items[0].Vector)
	avgVector := make([]float32, dim)

	maxItemsForLLM := 15

	for i, item := range items {
		content := ""
		if val, ok := item.Metadata["content"]; ok {
			content = fmt.Sprintf("%v", val)
		}

		if i < maxItemsForLLM {
			texts = append(texts, fmt.Sprintf("- %s", content))
		}

		// Sum all vectors in the cluster (not just the LLM subset) to compute a precise average.
		if len(item.Vector) == dim {
			for j, v := range item.Vector {
				avgVector[j] += v
			}
		}
	}

	// Vector Average
	for i := range avgVector {
		avgVector[i] /= float32(len(items))
	}

	// 3. Synthesis: LLM if available, otherwise deterministic fallback.
	var summary string
	if g.llm != nil {
		sysPrompt := "You are a cognitive memory consolidator for an AI agent. Read the following redundant memory snippets and synthesize them into a single, comprehensive, and clear memory/fact. Keep it concise but retain all key information. Return ONLY the synthesized text, nothing else."
		userPrompt := strings.Join(texts, "\n")

		slog.Info("[Cognitive Engine] Asking LLM to synthesize memories...", "cluster_size", len(items))

		summary, err = g.llm.Chat(sysPrompt, userPrompt)
		if err != nil || summary == "" {
			slog.Warn("[Cognitive Engine] LLM synthesis failed", "error", err)
			return
		}
		summary = strings.TrimSpace(strings.TrimPrefix(strings.TrimSuffix(summary, "```"), "```"))
	} else {
		// Deterministic fallback: pick the most graph-central member as master.
		slog.Info("[Cognitive Engine] No LLM available. Using most graph-central member as master.", "cluster_size", len(items))
		summary = g.pickCentralContent(indexName, items)
		if summary == "" {
			return
		}
	}

	// 4. Save Master Memory to DB
	masterID := fmt.Sprintf("consolidation_%d", time.Now().UnixNano())
	masterMeta := map[string]any{
		"content":            summary,
		"type":               "consolidated_memory",
		"_created_at":        float64(time.Now().Unix()),
		"derived_from_count": float64(len(items)),
	}

	err = g.eng.VAdd(indexName, masterID, avgVector, masterMeta)
	if err != nil {
		slog.Error("[Cognitive Engine] Failed to save master memory", "error", err)
		return
	}

	// 5. Transfer external graph edges from old memories to the master node.
	clusterSet := make(map[string]struct{})
	for _, item := range items {
		clusterSet[item.ID] = struct{}{}
	}

	skipEdges := map[string]bool{
		"consolidated_into":    true,
		"derived_from":         true,
		"analyzed_against":     true,
		"gap_analyzed":         true,
		"sentiment_analyzed":   true,
		"centrality_analyzed":  true,
		"decay_analyzed":       true,
		"suggests_link":        true,
		"contradicts":          true,
		"contradicted_by":      true,
		"focus_shifted":        true,
		"focus_shifted_by":     true,
		"sentiment_shift":      true,
		"sentiment_shifted_by": true,
		"became_central":       true,
		"centralized_by":       true,
		"knowledge_decay":      true,
		"decaying_in":          true,
	}

	for _, item := range items {
		oldID := item.ID

		// A. Outgoing edges (master -> target)
		outRels := g.eng.VGetRelations(indexName, oldID)
		for relType := range outRels {
			if skipEdges[relType] {
				continue
			}
			edges, found := g.eng.VGetEdges(indexName, oldID, relType, 0)
			if !found {
				continue
			}
			for _, edge := range edges {
				if _, inCluster := clusterSet[edge.TargetID]; inCluster {
					continue
				}
				if err := g.eng.VLink(indexName, masterID, edge.TargetID, relType, "", edge.Weight, edge.GetProps()); err != nil {
					slog.Warn("[Cognitive Engine] Failed to transfer outgoing edge", "error", err)
				}
			}
		}

		// B. Incoming edges (source -> master)
		inRels := g.eng.VGetIncomingRelations(indexName, oldID)
		for relType := range inRels {
			if skipEdges[relType] {
				continue
			}
			edges, found := g.eng.VGetIncomingEdges(indexName, oldID, relType, 0)
			if !found {
				continue
			}
			for _, edge := range edges {
				// In VGetIncomingEdges, TargetID is the source node.
				sourceID := edge.TargetID
				if _, inCluster := clusterSet[sourceID]; inCluster {
					continue
				}
				if err := g.eng.VLink(indexName, sourceID, masterID, relType, "", edge.Weight, edge.GetProps()); err != nil {
					slog.Warn("[Cognitive Engine] Failed to transfer incoming edge", "error", err)
				}
			}
		}
	}

	// 6. Archive old memories
	for _, item := range items {
		// Link: old memory --[consolidated_into]--> master memory
		if err := g.eng.VLink(indexName, item.ID, masterID, "consolidated_into", "derived_from", 1.0, nil); err != nil {
			slog.Warn("[Cognitive Engine] Failed to link consolidated memory", "from", item.ID, "error", err)
		}

		metaUpdate := map[string]any{
			"_archived":          true,
			"_consolidated_into": masterID,
		}
		if err := g.eng.VSetMetadata(indexName, item.ID, metaUpdate); err != nil {
			slog.Warn("[Cognitive Engine] Failed to archive memory", "id", item.ID, "error", err)
		}
	}

	slog.Info("[Cognitive Engine] Cluster successfully consolidated! 🧠",
		"master_id", masterID,
		"merged_count", len(items),
		"summary_preview", summary[:min(50, len(summary))]+"...")
}

// consolidateEpisodicToSemantic consolidates redundant episodic memories into
// a single semantic memory. This upgrades the knowledge from time-bound events
// to general facts.
func (g *Gardener) consolidateEpisodicToSemantic(indexName string, cluster MemoryCluster) {
	// 1. Fetch data for all memories in the cluster
	items, err := g.eng.VGetMany(indexName, cluster.MemberIDs)
	if err != nil || len(items) == 0 {
		return
	}

	// Verify all are episodic (safety check)
	for _, item := range items {
		layer := "episodic"
		if l, ok := item.Metadata["memory_layer"].(string); ok && l != "" {
			layer = l
		}
		if layer != "episodic" {
			slog.Warn("[Cognitive Engine] Skipping non-episodic memory in episodic consolidation", "id", item.ID, "layer", layer)
			return
		}
	}

	// 2. Prepare text and compute average vector
	var texts []string
	dim := len(items[0].Vector)
	avgVector := make([]float32, dim)
	maxItemsForLLM := 15

	for i, item := range items {
		content := ""
		if val, ok := item.Metadata["content"]; ok {
			content = fmt.Sprintf("%v", val)
		}
		if i < maxItemsForLLM {
			texts = append(texts, fmt.Sprintf("- %s", content))
		}
		if len(item.Vector) == dim {
			for j, v := range item.Vector {
				avgVector[j] += v
			}
		}
	}

	for i := range avgVector {
		avgVector[i] /= float32(len(items))
	}

	// 3. Synthesis via LLM or deterministic fallback
	var summary string
	if g.llm != nil {
		sysPrompt := "You are a cognitive memory consolidator. The following are multiple observations of similar events. Synthesize them into a single, general fact or pattern. This should be a semantic memory (a general truth), not an episodic one (a specific event). Return ONLY the synthesized text."
		userPrompt := strings.Join(texts, "\n")
		slog.Info("[Cognitive Engine] Synthesizing episodic cluster into semantic memory...", "cluster_size", len(items))
		summary, err = g.llm.Chat(sysPrompt, userPrompt)
		if err != nil || summary == "" {
			slog.Warn("[Cognitive Engine] LLM synthesis failed for semantic consolidation", "error", err)
			return
		}
		summary = strings.TrimSpace(strings.TrimPrefix(strings.TrimSuffix(summary, "```"), "```"))
	} else {
		// Deterministic fallback: use most central member
		summary = g.pickCentralContent(indexName, items)
		if summary == "" {
			return
		}
	}

	// 4. Create semantic master memory
	masterID := fmt.Sprintf("semantic_%d", time.Now().UnixNano())
	masterMeta := map[string]any{
		"content":            summary,
		"type":               "semantic_memory",
		"memory_layer":       "semantic",
		"_created_at":        float64(time.Now().Unix()),
		"_source_cluster":    strings.Join(cluster.MemberIDs, ","),
		"consolidated_count": float64(len(items)),
		"consolidated_from":  "episodic",
	}

	err = g.eng.VAdd(indexName, masterID, avgVector, masterMeta)
	if err != nil {
		slog.Error("[Cognitive Engine] Failed to save semantic memory", "error", err)
		return
	}

	// 5. Transfer edges (same logic as consolidateCluster)
	clusterSet := make(map[string]struct{})
	for _, item := range items {
		clusterSet[item.ID] = struct{}{}
	}

	skipEdges := map[string]bool{
		"consolidated_into":    true,
		"derived_from":         true,
		"analyzed_against":     true,
		"gap_analyzed":         true,
		"sentiment_analyzed":   true,
		"centrality_analyzed":  true,
		"decay_analyzed":       true,
		"suggests_link":        true,
		"contradicts":          true,
		"contradicted_by":      true,
		"focus_shifted":        true,
		"focus_shifted_by":     true,
		"sentiment_shift":      true,
		"sentiment_shifted_by": true,
		"became_central":       true,
		"centralized_by":       true,
		"knowledge_decay":      true,
		"decaying_in":          true,
	}

	for _, item := range items {
		oldID := item.ID
		outRels := g.eng.VGetRelations(indexName, oldID)
		for relType := range outRels {
			if skipEdges[relType] {
				continue
			}
			edges, found := g.eng.VGetEdges(indexName, oldID, relType, 0)
			if !found {
				continue
			}
			for _, edge := range edges {
				if _, inCluster := clusterSet[edge.TargetID]; inCluster {
					continue
				}
				if err := g.eng.VLink(indexName, masterID, edge.TargetID, relType, "", edge.Weight, edge.GetProps()); err != nil {
					slog.Warn("[Cognitive Engine] Failed to transfer edge to semantic memory", "error", err)
				}
			}
		}

		inRels := g.eng.VGetIncomingRelations(indexName, oldID)
		for relType := range inRels {
			if skipEdges[relType] {
				continue
			}
			edges, found := g.eng.VGetIncomingEdges(indexName, oldID, relType, 0)
			if !found {
				continue
			}
			for _, edge := range edges {
				sourceID := edge.TargetID
				if _, inCluster := clusterSet[sourceID]; inCluster {
					continue
				}
				if err := g.eng.VLink(indexName, sourceID, masterID, relType, "", edge.Weight, edge.GetProps()); err != nil {
					slog.Warn("[Cognitive Engine] Failed to transfer incoming edge", "error", err)
				}
			}
		}
	}

	// 6. Archive old episodic memories
	for _, item := range items {
		if err := g.eng.VLink(indexName, item.ID, masterID, "consolidated_into", "derived_from", 1.0, nil); err != nil {
			slog.Warn("[Cognitive Engine] Failed to link episodic to semantic", "from", item.ID, "error", err)
		}
		metaUpdate := map[string]any{
			"_archived":           true,
			"_consolidated_into":  masterID,
			"_consolidation_type": "episodic_to_semantic",
		}
		if err := g.eng.VSetMetadata(indexName, item.ID, metaUpdate); err != nil {
			slog.Warn("[Cognitive Engine] Failed to archive episodic memory", "id", item.ID, "error", err)
		}
	}

	slog.Info("[Cognitive Engine] Episodic memories consolidated into semantic memory! 🧠",
		"semantic_id", masterID,
		"episodic_count", len(items),
		"summary_preview", summary[:min(50, len(summary))]+"...")
}

// pickCentralContent returns the content of the most graph-connected member in the cluster.
// Used as a deterministic fallback when no LLM is available for synthesis.
func (g *Gardener) pickCentralContent(indexName string, items []core.VectorData) string {
	var bestContent string
	maxDegree := -1
	for _, item := range items {
		outRels := g.eng.VGetRelations(indexName, item.ID)
		inRels := g.eng.VGetIncomingRelations(indexName, item.ID)
		degree := 0
		for _, t := range outRels {
			degree += len(t)
		}
		for _, s := range inRels {
			degree += len(s)
		}
		content, _ := item.Metadata["content"].(string)
		if degree > maxDegree || (degree == maxDegree && len(content) > len(bestContent)) {
			maxDegree = degree
			bestContent = content
		}
	}
	return bestContent
}

// detectContradictions finds memories about the same topic that make conflicting claims.
func (g *Gardener) detectContradictions(indexName string) {
	// Small batch (50) because each pair triggers an LLM call.
	currentCursor := g.getCursor(indexName + "_contradictions")
	ids, nextCursor, err := g.eng.VGetIDsByCursor(indexName, currentCursor, 50)
	if err != nil || len(ids) == 0 {
		return
	}
	g.setCursor(indexName+"_contradictions", nextCursor)

	nodes, _ := g.eng.VGetMany(indexName, ids)

	for _, node := range nodes {
		contentA, ok := node.Metadata["content"].(string)
		if !ok || contentA == "" {
			continue
		}

		// Find semantically similar but non-identical memories (score 0.70–0.95).
		neighbors, _ := g.eng.VSearchWithScores(indexName, node.Vector, 5)

		for _, neighbor := range neighbors {
			if neighbor.ID == node.ID || neighbor.Score > 0.95 || neighbor.Score < 0.70 {
				continue
			}

			// Dedup via graph edge: skip if this pair was already analyzed.
			existingLinks, found := g.eng.VGetLinks(indexName, node.ID, "analyzed_against")
			if found {
				skip := false
				for _, link := range existingLinks {
					if link == neighbor.ID {
						skip = true
						break
					}
				}
				if skip {
					continue
				}
			}

			// Mark the pair as analyzed to prevent re-processing.
			if err := g.eng.VLink(indexName, node.ID, neighbor.ID, "analyzed_against", "analyzed_against", 1.0, nil); err != nil {
				slog.Warn("[Cognitive Engine] Failed to mark pair as analyzed", "error", err)
				continue
			}

			neighborData, err := g.eng.VGet(indexName, neighbor.ID)
			if err != nil {
				continue
			}
			contentB, ok := neighborData.Metadata["content"].(string)
			if !ok {
				continue
			}

			// Ask the LLM for a contradiction analysis.
			dateA := ""
			if ts, ok := node.Metadata["_created_at"].(float64); ok {
				dateA = time.Unix(int64(ts), 0).Format("2006-01-02")
			}
			dateB := ""
			if ts, ok := neighborData.Metadata["_created_at"].(float64); ok {
				dateB = time.Unix(int64(ts), 0).Format("2006-01-02")
			}

			sysPrompt := `Analyze the following two memory statements from an AI agent.
Consider their timestamps — the more recent memory is likely more accurate.
Do they logically contradict each other?
Return ONLY a valid JSON object:
{"contradiction": true/false, "reason": "...", "suggested_resolution": "...", "action_required": true/false}

Guidelines for action_required:
- true if the agent must manually investigate or choose which memory to keep
- false if the contradiction is minor or can be auto-resolved by preferring the newer memory

Guidelines for suggested_resolution:
- If timestamps differ significantly, suggest: "Keep the newer memory (from <date>) and archive the older one."
- If both are equally recent, suggest: "Verify which statement is correct and discard the other."
- If not a contradiction, set to ""`

			userPrompt := fmt.Sprintf("Memory A (from %s): %s\nMemory B (from %s): %s", dateA, contentA, dateB, contentB)

			respText, err := g.llm.Chat(sysPrompt, userPrompt)
			if err != nil {
				continue
			}

			// Extract JSON from the response, stripping any markdown or extra text.
			startIdx := strings.Index(respText, "{")
			endIdx := strings.LastIndex(respText, "}")
			if startIdx != -1 && endIdx != -1 && endIdx > startIdx {
				respText = respText[startIdx : endIdx+1]
			}

			var aiAnalysis llmContradictionResponse
			if err := json.Unmarshal([]byte(respText), &aiAnalysis); err == nil {
				if aiAnalysis.Contradiction {
					slog.Info("[Cognitive Engine] ⚠️ Contradiction Detected!", "reason", aiAnalysis.Reason)

					reflectionID := fmt.Sprintf("reflection_%d", time.Now().UnixNano())
					g.reflectionsMu.Lock()
					g.newReflections = append(g.newReflections, reflectionID)
					g.reflectionsMu.Unlock()

					// Zero-cost embedding: average of the two conflicting vectors.
					dim := len(node.Vector)
					avgVec := make([]float32, dim)
					for i := range node.Vector {
						avgVec[i] = (node.Vector[i] + neighborData.Vector[i]) / 2.0
					}

					meta := map[string]any{
						"type":                 "reflection",
						"content":              fmt.Sprintf("Conflict detected: %s", aiAnalysis.Reason),
						"status":               "unresolved",
						"confidence":           0.7,
						"suggested_resolution": aiAnalysis.SuggestedResolution,
						"action_required":      aiAnalysis.ActionRequired,
						"_created_at":          float64(time.Now().Unix()),
					}

					g.eng.VAdd(indexName, reflectionID, avgVec, meta)

					// Link both memories to the reflection node.
					if err := g.eng.VLink(indexName, reflectionID, node.ID, "contradicts", "contradicted_by", 1.0, nil); err != nil {
						slog.Warn("[Cognitive Engine] Failed to link contradiction", "error", err)
					}
					if err := g.eng.VLink(indexName, reflectionID, neighbor.ID, "contradicts", "contradicted_by", 1.0, nil); err != nil {
						slog.Warn("[Cognitive Engine] Failed to link contradiction", "error", err)
					}
				}
			}
		}
	}
}

// detectImportanceShifts detects entities that have suddenly become popular
// by comparing edge timestamps over the last 3 days.
func (g *Gardener) detectImportanceShifts(indexName string) {
	currentCursor := g.getCursor(indexName + "_shifts")
	ids, nextCursor, err := g.eng.VGetIDsByCursor(indexName, currentCursor, 200)
	if err != nil || len(ids) == 0 {
		return
	}
	g.setCursor(indexName+"_shifts", nextCursor)

	now := time.Now().UnixNano()
	threeDaysAgo := now - (3 * 24 * int64(time.Hour))

	for _, id := range ids {
		edges, found := g.eng.VGetIncomingEdges(indexName, id, "mentions", 0)
		if !found || len(edges) < 5 {
			continue // Too few links to be significant.
		}

		recentMentions := 0
		oldMentions := 0

		// Count when edges were created (time-travel query).
		for _, edge := range edges {
			if edge.CreatedAt > threeDaysAgo {
				recentMentions++
			} else {
				oldMentions++
			}
		}

		// Spike heuristic: more mentions in the last 3 days than in all prior history.
		if recentMentions > 5 && recentMentions > (oldMentions*2) {
			slog.Info("[Cognitive Engine] 📈 Importance Shift Detected!", "entity", id, "recent_mentions", recentMentions)

			// Anti-spam: skip if a reflection already exists for this entity.
			alreadyFlagged := false
			if existingRefs, ok := g.eng.VGetIncoming(indexName, id, "focus_shifted"); ok {
				if len(existingRefs) > 0 {
					alreadyFlagged = true
				}
			}

			if !alreadyFlagged {
				reflectionID := fmt.Sprintf("reflection_%d", time.Now().UnixNano())
				g.reflectionsMu.Lock()
				g.newReflections = append(g.newReflections, reflectionID)
				g.reflectionsMu.Unlock()

				nodeData, _ := g.eng.VGet(indexName, id)

				confidence := math.Min(1.0, float64(recentMentions)/10.0)
				meta := map[string]any{
					"type":        "reflection",
					"content":     fmt.Sprintf("Sudden surge of interest in '%s'. Received %d new mentions recently.", id, recentMentions),
					"status":      "insight",
					"confidence":  confidence,
					"_created_at": float64(time.Now().Unix()),
				}

				g.eng.VAdd(indexName, reflectionID, nodeData.Vector, meta)
				if err := g.eng.VLink(indexName, reflectionID, id, "focus_shifted", "focus_shifted_by", 1.0, nil); err != nil {
					slog.Warn("[Cognitive Engine] Failed to link importance shift", "error", err)
				}
			}
		}
	}
}

// ForceThink triggers a cognitive cycle immediately for a specific index.
// Used by the HTTP API for manual intervention or after heavy bulk imports.
func (g *Gardener) ForceThink(indexName string) {
	if !g.eng.IndexExists(indexName) {
		slog.Warn("[Cognitive Engine] Cannot think on missing index", "index", indexName)
		return
	}

	// Security check: verify index is in the target list.
	if !g.cfg.isIndexAllowed(indexName) {
		slog.Warn("[Cognitive Engine] Index not in target list for cognitive analysis", "index", indexName)
		return
	}

	slog.Info("[Cognitive Engine] Manual reflection cycle triggered.", "index", indexName, "mode", g.cfg.Mode)

	g.reflectionsMu.Lock()
	g.newReflections = nil
	g.reflectionsMu.Unlock()

	// Look up the index language for sentiment analysis.
	var indexLang string
	if info, err := g.eng.DB.GetSingleVectorIndexInfoAPI(indexName); err == nil {
		indexLang = info.TextLanguage
	}

	// =====================================================================
	// LAYER 1: BASIC (Fast, Math & Graph Only, NO LLM)
	// =====================================================================
	g.detectKnowledgeGaps(indexName)
	g.detectImportanceShifts(indexName)
	g.detectSentimentShifts(indexName, indexLang)
	g.detectCentralityShifts(indexName)
	g.detectForgettingPatterns(indexName)

	// Consolidation: cluster finding is pure math (no LLM needed).
	clusters := g.findRedundantClusters(indexName, 0.90, 5)
	for _, cluster := range clusters {
		g.consolidateCluster(indexName, cluster)
	}

	// Advanced-only: contradiction detection (requires LLM).
	if g.llm != nil && (g.cfg.Mode == "advanced" || g.cfg.Mode == "meta") {
		g.detectContradictions(indexName)
		g.detectUserPreferences(indexName)
		g.detectRepeatedFailures(indexName)
		g.detectKnowledgeEvolution(indexName)
	}

	// Epistemic resolution: resolve volatile beliefs using VBeliefState (Fase 3)
	if g.cfg.EpistemicResolutionEnabled {
		g.resolveVolatileBeliefs(indexName)
	}
}

// SummarizeSession creates a semantic summary of a session and archives episodic memories.
// This is called when end_session is triggered via MCP or HTTP API.
func (g *Gardener) SummarizeSession(indexName, sessionID string) error {
	if !g.eng.IndexExists(indexName) {
		return fmt.Errorf("index %s does not exist", indexName)
	}

	slog.Info("[Cognitive Engine] Summarizing session", "index", indexName, "session", sessionID)

	// 1. Retrieve all memories belonging to this session
	filter := fmt.Sprintf("session_id='%s' AND type='memory'", sessionID)
	memoryIDs, err := g.eng.VFilter(indexName, filter, 0) // 0 = no limit
	if err != nil {
		return fmt.Errorf("failed to retrieve session memories: %w", err)
	}

	if len(memoryIDs) == 0 {
		slog.Info("[Cognitive Engine] No memories found for session", "session", sessionID)
		return nil
	}

	// 2. Fetch memory contents
	memories, _ := g.eng.VGetMany(indexName, memoryIDs)
	if len(memories) == 0 {
		return nil
	}

	// Sort by timestamp
	sort.Slice(memories, func(i, j int) bool {
		ti := g.getTimestamp(memories[i].Metadata)
		tj := g.getTimestamp(memories[j].Metadata)
		return ti < tj
	})

	// 3. Extract contents for summarization
	var contents []string
	for _, mem := range memories {
		if content, ok := mem.Metadata["content"].(string); ok && content != "" {
			contents = append(contents, content)
		}
	}

	if len(contents) == 0 {
		slog.Info("[Cognitive Engine] No content to summarize", "session", sessionID)
		return nil
	}

	// 4. Generate summary (LLM or deterministic fallback)
	summaryContent, keyPoints, decisions, followUp := g.generateSessionSummary(contents)

	// 5. Create summary node
	summaryID := fmt.Sprintf("summary::%s", sessionID)
	summaryMeta := map[string]any{
		"type":         "session_summary",
		"memory_layer": "semantic",
		"content":      summaryContent,
		"key_points":   keyPoints,
		"decisions":    decisions,
		"follow_up":    followUp,
		"session_id":   sessionID,
		"memory_count": len(memories),
		"_pinned":      true, // Summary is important, keep it
		"timestamp":    time.Now().Format(time.RFC3339),
		"_created_at":  float64(time.Now().Unix()),
	}

	// Try zero-vector insert (bootstrap if needed)
	err = g.eng.VAdd(indexName, summaryID, nil, summaryMeta)
	if err != nil && strings.Contains(err.Error(), "dimension unknown") {
		// Bootstrap with embedding of summary content
		vec, embedErr := g.embedContent(summaryContent)
		if embedErr != nil {
			slog.Warn("[Cognitive Engine] Failed to embed summary, using zero vector", "error", embedErr)
			// Continue anyway - we can't embed but we can still store
		} else {
			err = g.eng.VAdd(indexName, summaryID, vec, summaryMeta)
		}
	}
	if err != nil && !strings.Contains(err.Error(), "dimension unknown") {
		return fmt.Errorf("failed to create summary node: %w", err)
	}

	// 6. Link summary to session
	g.eng.VLink(indexName, summaryID, sessionID, "summarizes", "", 1.0, nil)

	// 7. Archive episodic memories
	archivedCount := 0
	for _, mem := range memories {
		layer := "episodic"
		if l, ok := mem.Metadata["memory_layer"].(string); ok && l != "" {
			layer = l
		}
		// Only archive episodic memories
		if layer == "episodic" {
			updateProps := map[string]any{
				"_archived":   true,
				"archived_by": summaryID,
				"archived_at": time.Now().Format(time.RFC3339),
			}
			if err := g.eng.VSetMetadata(indexName, mem.ID, updateProps); err == nil {
				archivedCount++
			}
		}
	}

	slog.Info("[Cognitive Engine] Session summarized",
		"session", sessionID,
		"memories", len(memories),
		"archived", archivedCount,
		"summary", summaryID)

	return nil
}

// UserProfile represents the persistent personality profile of a user.
// Used internally for LLM interactions and stored in metadata.
type UserProfile struct {
	UserID             string   `json:"user_id"`
	CommunicationStyle string   `json:"communication_style"` // "concise", "verbose", "technical"
	Language           string   `json:"language"`            // "it", "en", etc.
	ExpertiseAreas     []string `json:"expertise_areas"`     // ["Go", "databases"]
	Dislikes           []string `json:"dislikes"`            // Anti-preferences
	ResponseLength     string   `json:"response_length"`     // "short", "medium", "long"
	Confidence         float64  `json:"confidence"`
	InteractionCount   int      `json:"interaction_count"`
	LastUpdated        int64    `json:"last_updated"`
	ProfileData        string   `json:"profile_data"` // Full JSON for LLM
}

// UpdateUserProfile updates the user profile based on recent interactions.
// Called when unassimilatedInteractions count exceeds ProfileUpdateThreshold.
func (g *Gardener) UpdateUserProfile(indexName, userID string) error {
	if !g.cfg.EnableUserProfiling {
		return nil
	}

	if !g.eng.IndexExists(indexName) {
		return fmt.Errorf("index %s does not exist", indexName)
	}

	slog.Info("[Cognitive Engine] Updating user profile", "index", indexName, "user", userID)

	// 1. Get recent user_interaction memories
	filter := fmt.Sprintf("user_id='%s' AND tags CONTAINS 'user_interaction'", userID)
	ids, err := g.eng.VFilter(indexName, filter, g.cfg.ProfileUpdateThreshold)
	if err != nil {
		return fmt.Errorf("failed to get user interactions: %w", err)
	}

	if len(ids) == 0 {
		return nil
	}

	// 2. Fetch interaction contents
	memories, _ := g.eng.VGetMany(indexName, ids)
	if len(memories) == 0 {
		return nil
	}

	// Sort by timestamp (newest first for LLM context)
	sort.Slice(memories, func(i, j int) bool {
		ti := getMemTimestamp(memories[i].Metadata)
		tj := getMemTimestamp(memories[j].Metadata)
		return ti > tj
	})

	var interactions []string
	var timestamps []string
	for _, mem := range memories {
		if content, ok := mem.Metadata["content"].(string); ok && content != "" {
			ts := ""
			if t, ok := mem.Metadata["_created_at"].(float64); ok {
				ts = time.Unix(int64(t), 0).Format("2006-01-02 15:04")
			}
			interactions = append(interactions, fmt.Sprintf("[%s] %s", ts, content))
			timestamps = append(timestamps, ts)
		}
	}

	if len(interactions) == 0 {
		return nil
	}

	// 3. Get current profile or create default
	profileID := fmt.Sprintf("_profile::%s", userID)
	currentProfile := UserProfile{UserID: userID, Confidence: 0.0}

	data, err := g.eng.VGet(indexName, profileID)
	currentProfile.UserID = userID
	currentProfile.Confidence = 0.0

	if err == nil {
		currentProfile.CommunicationStyle = getString(data.Metadata, "communication_style")
		currentProfile.Language = getString(data.Metadata, "language")
		currentProfile.ResponseLength = getString(data.Metadata, "response_length")
		currentProfile.Confidence = getFloat(data.Metadata, "confidence")
		currentProfile.InteractionCount = int(getFloat(data.Metadata, "interaction_count"))
		currentProfile.LastUpdated = int64(getFloat(data.Metadata, "last_updated"))

		if areas, ok := data.Metadata["expertise_areas"].(string); ok && areas != "" {
			currentProfile.ExpertiseAreas = strings.Split(areas, ",")
		}
		if dis, ok := data.Metadata["dislikes"].(string); ok && dis != "" {
			currentProfile.Dislikes = strings.Split(dis, ",")
		}
		if pd, ok := data.Metadata["profile_data"].(string); ok {
			currentProfile.ProfileData = pd
		}
	}

	// 4. Generate updated profile (LLM or fallback)
	var updatedProfile UserProfile
	if g.llm != nil {
		updatedProfile = g.generateLLMProfileUpdate(currentProfile, interactions, timestamps)
	} else {
		updatedProfile = g.generateDeterministicProfileUpdate(currentProfile, interactions)
	}

	// 5. Store updated profile using VSetMetadata
	expertiseStr := strings.Join(updatedProfile.ExpertiseAreas, ",")
	dislikesStr := strings.Join(updatedProfile.Dislikes, ",")

	meta := map[string]any{
		"type":                "user_profile",
		"user_id":             userID,
		"communication_style": updatedProfile.CommunicationStyle,
		"language":            updatedProfile.Language,
		"expertise_areas":     expertiseStr,
		"dislikes":            dislikesStr,
		"response_length":     updatedProfile.ResponseLength,
		"confidence":          updatedProfile.Confidence,
		"interaction_count":   float64(updatedProfile.InteractionCount),
		"last_updated":        float64(time.Now().Unix()),
		"_pinned":             true, // Profile is important, no decay
	}

	profileJSON, _ := json.Marshal(updatedProfile)
	meta["profile_data"] = string(profileJSON)

	// Use VSetMetadata for update (VMETA command in AOF)
	if err := g.eng.VSetMetadata(indexName, profileID, meta); err != nil {
		// If node doesn't exist, create it
		if strings.Contains(err.Error(), "not found") {
			err = g.eng.VAdd(indexName, profileID, nil, meta)
		}
		if err != nil {
			return fmt.Errorf("failed to save profile: %w", err)
		}
	}

	// 6. Reset unassimilated counter
	g.profileMutex.Lock()
	g.unassimilatedInteractions[userID] = 0
	g.profileMutex.Unlock()

	slog.Info("[Cognitive Engine] User profile updated",
		"user", userID,
		"confidence", updatedProfile.Confidence,
		"interactions", updatedProfile.InteractionCount)

	return nil
}

// generateLLMProfileUpdate uses LLM to update the user profile.
func (g *Gardener) generateLLMProfileUpdate(current UserProfile, interactions, timestamps []string) UserProfile {
	currentJSON := current.ProfileData
	if currentJSON == "" {
		currentJSON = "{}"
	}

	sysPrompt := `You are a user behavior analyst. Update the user profile based on recent interactions.

IMPORTANT INSTRUCTIONS:
1. If recent interactions contradict old preferences, the NEW preferences MUST override
2. Pay attention to timestamps - recent preferences have more weight
3. Extract both positives (likes, preferences) AND negatives (dislikes, anti-patterns)
4. Output valid JSON only

CURRENT PROFILE:
` + currentJSON + `

RECENT INTERACTIONS:
` + strings.Join(interactions, "\n") + `

Respond with JSON:
{
  "user_id": "...",
  "communication_style": "concise|verbose|technical|mixed",
  "language": "it|en|...",
  "expertise_areas": ["Go", "databases", ...],
  "dislikes": ["no markdown", "no java proposals", ...],
  "response_length": "short|medium|long",
  "confidence": 0.0-1.0,
  "interaction_count": ...,
  "last_updated": ...,
  "profile_data": "FULL JSON STRING FOR LLM"
}`

	respText, err := g.llm.Chat(sysPrompt, "")
	if err != nil {
		slog.Warn("[Cognitive Engine] LLM profile update failed, using fallback", "error", err)
		return g.generateDeterministicProfileUpdate(current, interactions)
	}

	var resp struct {
		UserID             string   `json:"user_id"`
		CommunicationStyle string   `json:"communication_style"`
		Language           string   `json:"language"`
		ExpertiseAreas     []string `json:"expertise_areas"`
		Dislikes           []string `json:"dislikes"`
		ResponseLength     string   `json:"response_length"`
		Confidence         float64  `json:"confidence"`
		InteractionCount   int      `json:"interaction_count"`
		LastUpdated        int64    `json:"last_updated"`
		ProfileData        string   `json:"profile_data"`
	}

	if err := json.Unmarshal([]byte(respText), &resp); err != nil {
		slog.Warn("[Cognitive Engine] Failed to parse LLM profile response", "error", err)
		return g.generateDeterministicProfileUpdate(current, interactions)
	}

	return resp
}

// generateDeterministicProfileUpdate creates a simple profile update without LLM.
func (g *Gardener) generateDeterministicProfileUpdate(current UserProfile, interactions []string) UserProfile {
	updated := current
	updated.InteractionCount = current.InteractionCount + len(interactions)
	updated.LastUpdated = time.Now().Unix()
	updated.Confidence = math.Min(1.0, float64(updated.InteractionCount)/50.0)

	// Simple keyword extraction from recent interactions
	recentTexts := strings.Join(interactions, " ")
	lowerText := strings.ToLower(recentTexts)

	if strings.Contains(lowerText, "breve") || strings.Contains(lowerText, "conciso") || strings.Contains(lowerText, "short") {
		updated.ResponseLength = "short"
	} else if strings.Contains(lowerText, "lungo") || strings.Contains(lowerText, "verbose") || strings.Contains(lowerText, "long") {
		updated.ResponseLength = "long"
	}

	if strings.Contains(lowerText, "italiano") || strings.Contains(lowerText, "italian") || strings.Contains(lowerText, "in italiano") {
		updated.Language = "it"
	} else if strings.Contains(lowerText, "english") || strings.Contains(lowerText, "in english") {
		updated.Language = "en"
	}

	if strings.Contains(lowerText, "non usare") || strings.Contains(lowerText, "no ") || strings.Contains(lowerText, "avoid") {
		updated.Dislikes = append(updated.Dislikes, "custom dislike detected")
	}

	profileJSON, _ := json.Marshal(updated)
	updated.ProfileData = string(profileJSON)

	return updated
}

// getString is a helper to safely extract string from metadata.
func getString(m map[string]any, key string) string {
	if v, ok := m[key].(string); ok {
		return v
	}
	return ""
}

// getFloat is a helper to safely extract float64 from metadata.
func getFloat(m map[string]any, key string) float64 {
	if v, ok := m[key].(float64); ok {
		return v
	}
	return 0
}

// getMemTimestamp extracts timestamp from memory metadata for sorting.
func getMemTimestamp(meta map[string]any) int64 {
	if ts, ok := meta["_created_at"].(float64); ok {
		return int64(ts)
	}
	if ts, ok := meta["timestamp"].(string); ok {
		if t, err := time.Parse(time.RFC3339, ts); err == nil {
			return t.Unix()
		}
	}
	return 0
}

// getTimestamp extracts timestamp from metadata for sorting.
func (g *Gardener) getTimestamp(meta map[string]any) int64 {
	if ts, ok := meta["_created_at"].(float64); ok {
		return int64(ts)
	}
	if ts, ok := meta["timestamp"].(string); ok {
		if t, err := time.Parse(time.RFC3339, ts); err == nil {
			return t.Unix()
		}
	}
	return 0
}

