// generateSessionSummary creates a summary from memory contents.
// Uses LLM if available, otherwise creates a deterministic bullet list.
func (g *Gardener) generateSessionSummary(contents []string) (summary string, keyPoints, decisions, followUp string) {
	if g.llm != nil {
		return g.generateLLMSessionSummary(contents)
	}
	return g.generateDeterministicSessionSummary(contents)
}

// generateLLMSessionSummary uses LLM to synthesize session content.
func (g *Gardener) generateLLMSessionSummary(contents []string) (summary string, keyPoints, decisions, followUp string) {
	// Build prompt
	userQuery := fmt.Sprintf(`Analyze this conversation/session and provide a structured summary.

Memories from the session:
%s

Respond with JSON only:
{
  "summary": "Brief overall summary (2-3 sentences)",
  "key_points": "Bullet list of main topics discussed",
  "decisions": "Any decisions made during the session",
  "follow_up": "Action items or follow-up tasks"
}`, strings.Join(contents, "\n- "))

	systemPrompt := "You are a helpful assistant that summarizes conversations into structured JSON."

	response, err := g.llm.Chat(systemPrompt, userQuery)
	if err != nil {
		slog.Warn("[Cognitive Engine] LLM summary failed, using fallback", "error", err)
		return g.generateDeterministicSessionSummary(contents)
	}

	// Try to parse JSON response
	var result struct {
		Summary   string `json:"summary"`
		KeyPoints string `json:"key_points"`
		Decisions string `json:"decisions"`
		FollowUp  string `json:"follow_up"`
	}
	if err := json.Unmarshal([]byte(response), &result); err != nil {
		// If JSON parsing fails, use response as summary
		return response, "", "", ""
	}

	return result.Summary, result.KeyPoints, result.Decisions, result.FollowUp
}

// generateDeterministicSessionSummary creates a simple bullet list summary.
func (g *Gardener) generateDeterministicSessionSummary(contents []string) (summary string, keyPoints, decisions, followUp string) {
	var sb strings.Builder
	sb.WriteString("Session Summary:\n\n")
	sb.WriteString("Key Points:\n")
	for i, content := range contents {
		if i >= 10 { // Limit to first 10 items
			sb.WriteString(fmt.Sprintf("\n... and %d more items", len(contents)-10))
			break
		}
		// Truncate long content
		display := content
		if len(display) > 100 {
			display = display[:100] + "..."
		}
		sb.WriteString(fmt.Sprintf("- %s\n", display))
	}

	return sb.String(), "", "", ""
}

// detectKnowledgeGaps finds concepts that are semantically very close but
// lack an explicit topological relationship in the graph.
func (g *Gardener) detectKnowledgeGaps(indexName string) {
	currentCursor := g.getCursor(indexName + "_gaps")
	ids, nextCursor, err := g.eng.VGetIDsByCursor(indexName, currentCursor, 100)
	if err != nil || len(ids) == 0 {
		return
	}
	g.setCursor(indexName+"_gaps", nextCursor)

	nodes, _ := g.eng.VGetMany(indexName, ids)

	for _, node := range nodes {
		// Only analyze entities and documents; skip raw chunks to reduce noise.
		nodeType, ok := node.Metadata["type"].(string)
		if !ok || (nodeType != "entity" && nodeType != "document") {
			continue
		}

		// Pre-load all relations once (not per neighbor).
		outRels := g.eng.VGetRelations(indexName, node.ID)
		inRels := g.eng.VGetIncomingRelations(indexName, node.ID)

		// Find top-5 semantically similar nodes (score > 0.85).
		neighbors, _ := g.eng.VSearchWithScores(indexName, node.Vector, 5)

		for _, neighbor := range neighbors {
			if neighbor.ID == node.ID || neighbor.Score < 0.85 {
				continue
			}

			neighborData, err := g.eng.VGet(indexName, neighbor.ID)
			if err != nil {
				continue
			}
			nType, ok := neighborData.Metadata["type"].(string)
			if !ok || (nType != "entity" && nType != "document") {
				continue
			}

			// Check if a direct graph edge exists between the two nodes (both directions).
			connected := false

			// Outgoing edges (node -> neighbor)
			for _, targets := range outRels {
				for _, t := range targets {
					if t == neighbor.ID {
						connected = true
						break
					}
				}
				if connected {
					break
				}
			}

			// Incoming edges (neighbor -> node)
			if !connected {
				for _, sources := range inRels {
					for _, s := range sources {
						if s == neighbor.ID {
							connected = true
							break
						}
					}
					if connected {
						break
					}
				}
			}

			// 5. Gap found: semantically close but topologically disconnected.
			if !connected {
				slog.Info("[Cognitive Engine] 🧩 Knowledge Gap Detected!", "node_a", node.ID, "node_b", neighbor.ID)

				// Dedup: check if this pair was already flagged.
				existingLinks, found := g.eng.VGetLinks(indexName, node.ID, "gap_analyzed")
				skip := false
				if found {
					for _, link := range existingLinks {
						if link == neighbor.ID {
							skip = true
							break
						}
					}
				}

				if !skip {
					if err := g.eng.VLink(indexName, node.ID, neighbor.ID, "gap_analyzed", "gap_analyzed", 1.0, nil); err != nil {
						slog.Warn("[Cognitive Engine] Failed to mark gap as analyzed", "error", err)
						continue
					}

					reflectionID := fmt.Sprintf("reflection_%d", time.Now().UnixNano())
					g.reflectionsMu.Lock()
					g.newReflections = append(g.newReflections, reflectionID)
					g.reflectionsMu.Unlock()

					dim := len(node.Vector)
					avgVec := make([]float32, dim)
					for i := range node.Vector {
						avgVec[i] = (node.Vector[i] + neighborData.Vector[i]) / 2.0
					}

					nameA := node.Metadata["name"]
					if nameA == nil {
						nameA = node.ID
					}
					nameB := neighborData.Metadata["name"]
					if nameB == nil {
						nameB = neighbor.ID
					}

					meta := map[string]any{
						"type":        "reflection",
						"content":     fmt.Sprintf("Implicit relationship discovered: '%v' and '%v' share high semantic similarity (%.2f) but lack an explicit graph connection. Consider linking them.", nameA, nameB, neighbor.Score),
						"status":      "insight",
						"confidence":  neighbor.Score,
						"_created_at": float64(time.Now().Unix()),
					}

					g.eng.VAdd(indexName, reflectionID, avgVec, meta)
					if err := g.eng.VLink(indexName, reflectionID, node.ID, "suggests_link", "", 1.0, nil); err != nil {
						slog.Warn("[Cognitive Engine] Failed to link knowledge gap", "error", err)
					}
					if err := g.eng.VLink(indexName, reflectionID, neighbor.ID, "suggests_link", "", 1.0, nil); err != nil {
						slog.Warn("[Cognitive Engine] Failed to link knowledge gap", "error", err)
					}
				}
			}
		}
	}
}

// detectUserPreferences scans recent memories tagged as user interactions
// and uses the LLM to extract structured user preferences.
func (g *Gardener) detectUserPreferences(indexName string) {
	currentCursor := g.getCursor(indexName + "_preferences")
	ids, nextCursor, err := g.eng.VGetIDsByCursor(indexName, currentCursor, 200)
	if err != nil || len(ids) == 0 {
		return
	}
	g.setCursor(indexName+"_preferences", nextCursor)

	nodes, _ := g.eng.VGetMany(indexName, ids)

	// Filter for memories tagged as user interactions or observations.
	var relevantIDs []string
	var promptLines []string
	for _, node := range nodes {
		tags, ok := node.Metadata["tags"].([]any)
		if !ok {
			continue
		}
		isRelevant := false
		for _, t := range tags {
			tagStr, _ := t.(string)
			if tagStr == "user_interaction" || tagStr == "observation" {
				isRelevant = true
				break
			}
		}
		if !isRelevant {
			continue
		}

		content, _ := node.Metadata["content"].(string)
		if content == "" {
			continue
		}

		dateStr := ""
		if ts, ok := node.Metadata["_created_at"].(float64); ok {
			dateStr = time.Unix(int64(ts), 0).Format("2006-01-02")
		}

		relevantIDs = append(relevantIDs, node.ID)
		promptLines = append(promptLines, fmt.Sprintf("- [%s] %s", dateStr, content))
	}

	if len(promptLines) < 2 {
		return // Not enough data to extract meaningful preferences.
	}

	sysPrompt := `You are a user behavior analyst for an AI agent. Analyze the following interaction memories and extract structured user preferences.
Return ONLY a valid JSON object:
{"preferences_discovered": {"key": "value", ...}, "recommendation": "..."}

Guidelines:
- Extract behavioral patterns (communication style, time preferences, topic interests).
- Use descriptive keys (e.g., "communication_style", "preferred_meeting_time").
- If no clear preferences emerge, return empty preferences_discovered.
- The recommendation should suggest how the agent should adapt its behavior.`

	userPrompt := "User interaction memories:\n" + strings.Join(promptLines, "\n")

	slog.Info("[Cognitive Engine] Analyzing user preferences...", "memory_count", len(promptLines))

	respText, err := g.llm.Chat(sysPrompt, userPrompt)
	if err != nil {
		return
	}

	// Extract JSON from the response.
	startIdx := strings.Index(respText, "{")
	endIdx := strings.LastIndex(respText, "}")
	if startIdx != -1 && endIdx != -1 && endIdx > startIdx {
		respText = respText[startIdx : endIdx+1]
	}

	var aiResp llmPreferenceResponse
	if err := json.Unmarshal([]byte(respText), &aiResp); err != nil {
		return
	}

	if len(aiResp.PreferencesDiscovered) == 0 {
		return // No preferences found.
	}

	// Create a user_profile_insight node.
	insightID := fmt.Sprintf("user_profile_%d", time.Now().UnixNano())

	// Use the first source memory's vector as a base (average would be ideal but this is simpler).
	vec, err := g.eng.VGet(indexName, relevantIDs[0])
	if err != nil || len(vec.Vector) == 0 {
		slog.Warn("[Cognitive Engine] Skipping user preferences: no valid vector for first memory")
		return
	}
	avgVec := make([]float32, len(vec.Vector))
	for _, id := range relevantIDs {
		d, err := g.eng.VGet(indexName, id)
		if err != nil || len(d.Vector) != len(avgVec) {
			continue
		}
		for j, v := range d.Vector {
			avgVec[j] += v
		}
	}
	for j := range avgVec {
		avgVec[j] /= float32(len(relevantIDs))
	}

	confidence := math.Min(1.0, float64(len(promptLines))/10.0)

	meta := map[string]any{
		"type":                "user_profile_insight",
		"content":             aiResp.Recommendation,
		"preferences":         aiResp.PreferencesDiscovered,
		"status":              "active",
		"confidence":          confidence,
		"source_memory_count": float64(len(relevantIDs)),
		"_created_at":         float64(time.Now().Unix()),
	}

	if err := g.eng.VAdd(indexName, insightID, avgVec, meta); err != nil {
		slog.Error("[Cognitive Engine] Failed to save user profile insight", "error", err)
		return
	}

	// Link to source memories.
	for _, srcID := range relevantIDs {
		if err := g.eng.VLink(indexName, insightID, srcID, "derived_from_interactions", "interaction_of", 1.0, nil); err != nil {
			slog.Warn("[Cognitive Engine] Failed to link user preference", "error", err)
		}
	}

	slog.Info("[Cognitive Engine] User profile insight created.",
		"insight_id", insightID,
		"preferences_count", len(aiResp.PreferencesDiscovered),
		"source_memories", len(relevantIDs))
}

// detectSentimentShifts compares past vs recent sentiment for an entity
// and detects opinion reversals over a 2-week window.
func (g *Gardener) detectSentimentShifts(indexName string, lang string) {
	lex, ok := sentimentLexicons[lang]
	if !ok {
		return // Unsupported language — skip sentiment analysis.
	}

	currentCursor := g.getCursor(indexName + "_sentiment")
	ids, nextCursor, err := g.eng.VGetIDsByCursor(indexName, currentCursor, 100)
	if err != nil || len(ids) == 0 {
		return
	}
	g.setCursor(indexName+"_sentiment", nextCursor)

	now := time.Now().UnixNano()
	twoWeeksAgo := now - (14 * 24 * int64(time.Hour))

	for _, id := range ids {
		edges, found := g.eng.VGetIncomingEdges(indexName, id, "mentions", 0)
		if !found || len(edges) < 4 {
			continue // Not enough memories to establish a pattern.
		}

		var pastScore, recentScore float64
		var pastCount, recentCount int

		for _, edge := range edges {
			// Note: edge.TargetID is the source node for incoming edges.
			sourceData, err := g.eng.VGet(indexName, edge.TargetID)
			if err != nil {
				continue
			}

			content, ok := sourceData.Metadata["content"].(string)
			if !ok {
				continue
			}

			content = strings.ToLower(content)
			score := 0.0
			for _, w := range lex.Positive {
				if strings.Contains(content, w) {
					score += 1.0
				}
			}
			for _, w := range lex.Negative {
				if strings.Contains(content, w) {
					score -= 1.0
				}
			}

			if edge.CreatedAt < twoWeeksAgo {
				pastScore += score
				pastCount++
			} else {
				recentScore += score
				recentCount++
			}
		}

		if pastCount > 0 && recentCount > 0 {
			avgPast := pastScore / float64(pastCount)
			avgRecent := recentScore / float64(recentCount)
			delta := avgRecent - avgPast

			// Strong sentiment shift detected (e.g., negative to positive).
			if math.Abs(delta) >= 1.5 {
				links, found := g.eng.VGetLinks(indexName, id, "sentiment_analyzed")
				if found && len(links) > 0 {
					continue
				}

				if err := g.eng.VLink(indexName, id, id, "sentiment_analyzed", "", 1.0, nil); err != nil { // Self-link as dedup marker
					slog.Warn("[Cognitive Engine] Failed to mark sentiment as analyzed", "error", err)
					continue
				}

				direction := "positive"
				if delta < 0 {
					direction = "negative"
				}

				slog.Info("[Cognitive Engine] 🎭 Sentiment Shift Detected!", "entity", id, "shift", direction)

				nodeData, _ := g.eng.VGet(indexName, id)
				reflectionID := fmt.Sprintf("reflection_%d", time.Now().UnixNano())
				g.reflectionsMu.Lock()
				g.newReflections = append(g.newReflections, reflectionID)
				g.reflectionsMu.Unlock()
				evidenceRatio := math.Min(1.0, float64(pastCount+recentCount)/8.0)
				confidence := math.Min(1.0, (math.Abs(delta)/3.0)*evidenceRatio)
				meta := map[string]any{
					"type":        "reflection",
					"content":     fmt.Sprintf("Sentiment shift detected for '%s'. Opinion has evolved in a heavily %s direction over the last 2 weeks.", id, direction),
					"status":      "insight",
					"confidence":  confidence,
					"_created_at": float64(time.Now().Unix()),
				}
				g.eng.VAdd(indexName, reflectionID, nodeData.Vector, meta)
				if err := g.eng.VLink(indexName, reflectionID, id, "sentiment_shift", "sentiment_shifted_by", 1.0, nil); err != nil {
					slog.Warn("[Cognitive Engine] Failed to link sentiment shift", "error", err)
				}
			}
		}
	}
}

// detectCentralityShifts detects nodes whose degree centrality has tripled
// in the last 30 days using time-travel graph queries.
func (g *Gardener) detectCentralityShifts(indexName string) {
	currentCursor := g.getCursor(indexName + "_centrality")
	ids, nextCursor, err := g.eng.VGetIDsByCursor(indexName, currentCursor, 100)
	if err != nil || len(ids) == 0 {
		return
	}
	g.setCursor(indexName+"_centrality", nextCursor)

	now := time.Now().UnixNano()
	oneMonthAgo := now - (30 * 24 * int64(time.Hour))

	for _, id := range ids {
		// Current degree centrality.
		outRelsNow := g.eng.VGetRelations(indexName, id)
		inRelsNow := g.eng.VGetIncomingRelations(indexName, id)
		degreeNow := 0
		for _, targets := range outRelsNow {
			degreeNow += len(targets)
		}
		for _, sources := range inRelsNow {
			degreeNow += len(sources)
		}

		// Skip low-connectivity nodes.
		if degreeNow < 10 {
			continue
		}

		// Degree centrality 30 days ago (time-travel query).
		degreePast := 0
		for rel := range outRelsNow {
			if edges, found := g.eng.VGetEdges(indexName, id, rel, oneMonthAgo); found {
				degreePast += len(edges)
			}
		}
		for rel := range inRelsNow {
			if edges, found := g.eng.VGetIncomingEdges(indexName, id, rel, oneMonthAgo); found {
				degreePast += len(edges)
			}
		}

		// Centrality has more than tripled.
		if degreePast > 0 && float64(degreeNow) > float64(degreePast)*3.0 {
			links, found := g.eng.VGetLinks(indexName, id, "centrality_analyzed")
			if found && len(links) > 0 {
				continue
			}
			if err := g.eng.VLink(indexName, id, id, "centrality_analyzed", "", 1.0, nil); err != nil {
				slog.Warn("[Cognitive Engine] Failed to mark centrality as analyzed", "error", err)
				continue
			}

			slog.Info("[Cognitive Engine] 🕸️ Centrality Explosion Detected!", "entity", id, "growth", degreeNow-degreePast)

			nodeData, _ := g.eng.VGet(indexName, id)
			reflectionID := fmt.Sprintf("reflection_%d", time.Now().UnixNano())
			g.reflectionsMu.Lock()
			g.newReflections = append(g.newReflections, reflectionID)
			g.reflectionsMu.Unlock()
			confidence := math.Min(1.0, float64(degreeNow)/float64(degreePast)/5.0)
			meta := map[string]any{
				"type":        "reflection",
				"content":     fmt.Sprintf("Graph Centrality Shift: '%s' has become a core concept in the knowledge base, growing from %d to %d connections in 30 days.", id, degreePast, degreeNow),
				"status":      "insight",
				"confidence":  confidence,
				"_created_at": float64(time.Now().Unix()),
			}
			g.eng.VAdd(indexName, reflectionID, nodeData.Vector, meta)
			if err := g.eng.VLink(indexName, reflectionID, id, "became_central", "centralized_by", 1.0, nil); err != nil {
				slog.Warn("[Cognitive Engine] Failed to link centrality shift", "error", err)
			}
		}
	}
}

// detectForgettingPatterns finds historically important entities that have been
// abandoned for over 30 days.
func (g *Gardener) detectForgettingPatterns(indexName string) {
	currentCursor := g.getCursor(indexName + "_forgetting")
	ids, nextCursor, err := g.eng.VGetIDsByCursor(indexName, currentCursor, 200)
	if err != nil || len(ids) == 0 {
		return
	}
	g.setCursor(indexName+"_forgetting", nextCursor)

	now := time.Now().UnixNano()
	oneMonthAgo := now - (30 * 24 * int64(time.Hour))

	for _, id := range ids {
		edges, found := g.eng.VGetIncomingEdges(indexName, id, "mentions", 0)
		if !found || len(edges) < 5 {
			continue // Never significant enough to track.
		}

		recentActivity := false
		for _, edge := range edges {
			if edge.CreatedAt > oneMonthAgo {
				recentActivity = true
				break
			}
		}

		if !recentActivity {
			// Deduplicazione
			links, found := g.eng.VGetLinks(indexName, id, "decay_analyzed")
			if found && len(links) > 0 {
				continue
			}
			if err := g.eng.VLink(indexName, id, id, "decay_analyzed", "", 1.0, nil); err != nil {
				slog.Warn("[Cognitive Engine] Failed to mark decay as analyzed", "error", err)
				continue
			}

			slog.Info("[Cognitive Engine] 🍂 Knowledge Decay Detected!", "entity", id)

			nodeData, _ := g.eng.VGet(indexName, id)
			reflectionID := fmt.Sprintf("reflection_%d", time.Now().UnixNano())
			g.reflectionsMu.Lock()
			g.newReflections = append(g.newReflections, reflectionID)
			g.reflectionsMu.Unlock()
			confidence := math.Min(1.0, float64(len(edges))/10.0)
			meta := map[string]any{
				"type":        "reflection",
				"content":     fmt.Sprintf("Knowledge Decay: The concept '%s' was previously important (%d mentions) but hasn't been accessed or mentioned in over 30 days.", id, len(edges)),
				"status":      "insight",
				"confidence":  confidence,
				"_created_at": float64(time.Now().Unix()),
			}
			g.eng.VAdd(indexName, reflectionID, nodeData.Vector, meta)
			if err := g.eng.VLink(indexName, reflectionID, id, "knowledge_decay", "decaying_in", 1.0, nil); err != nil {
				slog.Warn("[Cognitive Engine] Failed to link knowledge decay", "error", err)
			}
		}
	}
}

// detectRepeatedFailures scans for agent actions that have failed repeatedly
// and uses the LLM to diagnose the root cause and suggest a fix.
func (g *Gardener) detectRepeatedFailures(indexName string) {
	now := time.Now()
	twentyFourHoursAgo := now.Add(-24 * time.Hour)
	minTimestamp := float64(twentyFourHoursAgo.Unix())

	// Use VFilter to efficiently find recent failed agent actions.
	filter := "type='agent_action' AND status='failed'"
	ids, err := g.eng.VFilter(indexName, filter, 500)
	if err != nil || len(ids) < 3 {
		return
	}

	nodes, _ := g.eng.VGetMany(indexName, ids)

	// Group failures by action, filtering to last 24h.
	type failureGroup struct {
		action string
		nodes  []core.VectorData
	}
	groups := make(map[string]*failureGroup)

	for _, node := range nodes {
		// Time filter: only consider failures from the last 24 hours.
		if ts, ok := node.Metadata["_created_at"].(float64); ok && ts < minTimestamp {
			continue
		}

		action, _ := node.Metadata["action"].(string)
		if action == "" {
			action = "unknown"
		}

		if _, exists := groups[action]; !exists {
			groups[action] = &failureGroup{action: action}
		}
		groups[action].nodes = append(groups[action].nodes, node)
	}

	for _, group := range groups {
		if len(group.nodes) < 3 {
			continue // Need at least 3 failures to detect a pattern.
		}

		// Dedup: check if any failure node in this group was already analyzed.
		alreadyAnalyzed := false
		for _, n := range group.nodes {
			existingLinks, found := g.eng.VGetLinks(indexName, n.ID, "failure_analyzed")
			if found && len(existingLinks) > 0 {
				alreadyAnalyzed = true
				break
			}
		}
		if alreadyAnalyzed {
			continue
		}

		// Mark the first node as analyzed.
		if err := g.eng.VLink(indexName, group.nodes[0].ID, group.nodes[0].ID, "failure_analyzed", "", 1.0, nil); err != nil {
			slog.Warn("[Cognitive Engine] Failed to mark failure as analyzed", "error", err)
			continue
		}

		// Build prompt with timestamps.
		var promptLines []string
		for _, n := range group.nodes {
			content, _ := n.Metadata["content"].(string)
			dateStr := "unknown"
			if ts, ok := n.Metadata["_created_at"].(float64); ok {
				dateStr = time.Unix(int64(ts), 0).Format("2006-01-02 15:04")
			}
			promptLines = append(promptLines, fmt.Sprintf("- [%s] %s", dateStr, content))
		}

		sysPrompt := `You are a debugging analyst for an AI agent. The agent has been repeatedly failing at the same action. Analyze the failure logs and identify the pattern.
Return ONLY a valid JSON object:
{"pattern": "...", "root_cause": "...", "recommendation": "...", "severity": "low|medium|high"}

Guidelines:
- pattern: concise description of what's going wrong
- root_cause: the underlying reason
- recommendation: specific fix the agent should apply
- severity: "high" if agent is completely blocked, "medium" if degraded, "low" if intermittent`

		userPrompt := fmt.Sprintf("Repeated failures for action \"%s\" (%d failures in last 24h):\n%s",
			group.action, len(group.nodes), strings.Join(promptLines, "\n"))

		slog.Info("[Cognitive Engine] Analyzing repeated failures...", "action", group.action, "count", len(group.nodes))

		respText, err := g.llm.Chat(sysPrompt, userPrompt)
		if err != nil {
			continue
		}

		startIdx := strings.Index(respText, "{")
		endIdx := strings.LastIndex(respText, "}")
		if startIdx != -1 && endIdx != -1 && endIdx > startIdx {
			respText = respText[startIdx : endIdx+1]
		}

		var aiResp llmFailurePatternResponse
		if err := json.Unmarshal([]byte(respText), &aiResp); err != nil {
			continue
		}

		if aiResp.Pattern == "" {
			continue
		}

		// Create failure_pattern node.
		patternID := fmt.Sprintf("failure_pattern_%d", time.Now().UnixNano())

		// Average vector from source failures.
		dim := len(group.nodes[0].Vector)
		avgVec := make([]float32, dim)
		for _, n := range group.nodes {
			if len(n.Vector) == dim {
				for j, v := range n.Vector {
					avgVec[j] += v
				}
			}
		}
		for j := range avgVec {
			avgVec[j] /= float32(len(group.nodes))
		}

		confidence := math.Min(1.0, float64(len(group.nodes))/10.0)

		meta := map[string]any{
			"type":          "failure_pattern",
			"content":       aiResp.Recommendation,
			"pattern":       aiResp.Pattern,
			"root_cause":    aiResp.RootCause,
			"severity":      aiResp.Severity,
			"status":        "unresolved",
			"confidence":    confidence,
			"failure_count": float64(len(group.nodes)),
			"_created_at":   float64(time.Now().Unix()),
		}

		if err := g.eng.VAdd(indexName, patternID, avgVec, meta); err != nil {
			slog.Error("[Cognitive Engine] Failed to save failure pattern", "error", err)
			continue
		}

		for _, n := range group.nodes {
			if err := g.eng.VLink(indexName, patternID, n.ID, "failure_pattern_of", "has_failure_pattern", 1.0, nil); err != nil {
				slog.Warn("[Cognitive Engine] Failed to link failure pattern", "error", err)
			}
		}

		slog.Info("[Cognitive Engine] Failure pattern detected!",
			"action", group.action,
			"pattern", aiResp.Pattern,
			"severity", aiResp.Severity)
	}
}

// detectKnowledgeEvolution analyzes how an entity's knowledge neighborhood has evolved
// over time using VExtractSubgraph time-travel snapshots at 3 points in time.
func (g *Gardener) detectKnowledgeEvolution(indexName string) {
	currentCursor := g.getCursor(indexName + "_evolution")
	ids, nextCursor, err := g.eng.VGetIDsByCursor(indexName, currentCursor, 100)
	if err != nil || len(ids) == 0 {
		return
	}
	g.setCursor(indexName+"_evolution", nextCursor)

	now := time.Now()
	oneDayAgo := now.Add(-24 * time.Hour).UnixNano()
	fifteenDaysAgo := now.Add(-15 * 24 * time.Hour).UnixNano()
	thirtyDaysAgo := now.Add(-30 * 24 * time.Hour).UnixNano()

	relations := []string{"mentions", "related_to", "about", "suggests_link", "consolidated_into", "derived_from"}

	processed := 0
	for _, id := range ids {
		if processed >= 3 {
			break // Limit to 3 entities per cycle to control cost.
		}

		// Only analyze high-centrality entities.
		inRels := g.eng.VGetIncomingRelations(indexName, id)
		inDegree := 0
		for _, sources := range inRels {
			inDegree += len(sources)
		}
		if inDegree < 15 {
			continue
		}

		// Must be an entity type.
		nodeData, err := g.eng.VGet(indexName, id)
		if err != nil {
			continue
		}
		nodeType, _ := nodeData.Metadata["type"].(string)
		if nodeType != "entity" {
			continue
		}

		// Dedup: skip if already analyzed.
		existingLinks, found := g.eng.VGetLinks(indexName, id, "evolution_analyzed")
		if found && len(existingLinks) > 0 {
			continue
		}

		// Mark as analyzed.
		if err := g.eng.VLink(indexName, id, id, "evolution_analyzed", "", 1.0, nil); err != nil {
			slog.Warn("[Cognitive Engine] Failed to mark entity as evolution-analyzed", "error", err)
			continue
		}

		// Extract 3 subgraph snapshots via time travel.
		subgraphPast, _ := g.eng.VExtractSubgraph(indexName, id, relations, 2, thirtyDaysAgo, nil, 0)
		subgraphMid, _ := g.eng.VExtractSubgraph(indexName, id, relations, 2, fifteenDaysAgo, nil, 0)
		subgraphNow, _ := g.eng.VExtractSubgraph(indexName, id, relations, 2, oneDayAgo, nil, 0)

		// Get topic name.
		topicName := id
		if name, ok := nodeData.Metadata["name"].(string); ok && name != "" {
			topicName = name
		}

		// Format subgraphs as readable text for the LLM.
		formatSnapshot := func(label string, sg *engine.SubgraphResult) string {
			if sg == nil || len(sg.Nodes) <= 1 {
				return fmt.Sprintf("%s: No connected knowledge yet.", label)
			}
			nodeNames := []string{}
			for _, n := range sg.Nodes {
				if n.ID == sg.RootID {
					continue
				}
				name := n.ID
				if nodeName, ok := n.Metadata["name"].(string); ok && nodeName != "" {
					name = nodeName
				} else if c, ok := n.Metadata["content"].(string); ok && len(c) > 50 {
					name = c[:50] + "..."
				}
				nodeNames = append(nodeNames, name)
			}
			return fmt.Sprintf("%s: %d connected nodes — %s", label, len(nodeNames), strings.Join(nodeNames, ", "))
		}

		snapshotText := fmt.Sprintf("Topic: %s\n%s\n%s\n%s",
			topicName,
			formatSnapshot("30 days ago", subgraphPast),
			formatSnapshot("15 days ago", subgraphMid),
			formatSnapshot("Today", subgraphNow),
		)

		sysPrompt := `You are a knowledge evolution analyst for an AI agent. You are given 3 snapshots of what the agent knew about a specific topic at 3 different points in time. Analyze how the agent's understanding evolved and identify what's still missing.
Return ONLY a valid JSON object:
{"timeline": "...", "competency_level": "beginner|intermediate|advanced|expert", "knowledge_gaps": ["gap1", "gap2"], "next_steps": "..."}

Guidelines:
- timeline: describe the evolution in 3 phases
- competency_level: rate the agent's current knowledge depth
- knowledge_gaps: list specific topics the agent should study next
- next_steps: concrete recommendation for what to learn/do next`

		slog.Info("[Cognitive Engine] Analyzing knowledge evolution...", "entity", topicName, "in_degree", inDegree)

		respText, err := g.llm.Chat(sysPrompt, snapshotText)
		if err != nil {
			continue
		}

		startIdx := strings.Index(respText, "{")
		endIdx := strings.LastIndex(respText, "}")
		if startIdx != -1 && endIdx != -1 && endIdx > startIdx {
			respText = respText[startIdx : endIdx+1]
		}

		var aiResp llmEvolutionResponse
		if err := json.Unmarshal([]byte(respText), &aiResp); err != nil {
			continue
		}

		if aiResp.Timeline == "" {
			continue
		}

		// Create knowledge_evolution node.
		evoID := fmt.Sprintf("knowledge_evolution_%d", time.Now().UnixNano())

		confidence := math.Min(1.0, float64(inDegree)/20.0)

		meta := map[string]any{
			"type":             "knowledge_evolution",
			"content":          aiResp.NextSteps,
			"topic":            topicName,
			"timeline":         aiResp.Timeline,
			"competency_level": aiResp.CompetencyLevel,
			"status":           "active",
			"confidence":       confidence,
			"_created_at":      float64(time.Now().Unix()),
		}

		if len(aiResp.KnowledgeGaps) > 0 {
			gapAnys := make([]any, len(aiResp.KnowledgeGaps))
			for i, g := range aiResp.KnowledgeGaps {
				gapAnys[i] = g
			}
			meta["knowledge_gaps"] = gapAnys
		}

		if err := g.eng.VAdd(indexName, evoID, nodeData.Vector, meta); err != nil {
			slog.Error("[Cognitive Engine] Failed to save knowledge evolution", "error", err)
			continue
		}

		if err := g.eng.VLink(indexName, evoID, id, "evolution_of", "evolved_by", 1.0, nil); err != nil {
			slog.Warn("[Cognitive Engine] Failed to link knowledge evolution", "error", err)
		}

		slog.Info("[Cognitive Engine] Knowledge evolution tracked.",
			"topic", topicName,
			"competency", aiResp.CompetencyLevel,
			"gaps_count", len(aiResp.KnowledgeGaps))

		processed++
	}
}

// detectCrossValidator checks if the same entity was flagged by multiple detector types
// in the current cycle and creates a high-confidence composite reflection.
func (g *Gardener) detectCrossValidator(indexName string) {
	g.reflectionsMu.Lock()
	if len(g.newReflections) == 0 {
		g.reflectionsMu.Unlock()
		return
	}
	// Make a copy of reflections to work with outside the lock
	reflectionsCopy := make([]string, len(g.newReflections))
	copy(reflectionsCopy, g.newReflections)
	g.reflectionsMu.Unlock()

	detectorEdgeMap := map[string]string{
		"focus_shifted":   "importance",
		"sentiment_shift": "sentiment",
		"became_central":  "centrality",
		"knowledge_decay": "forgetting",
		"suggests_link":   "knowledge_gap",
		"contradicts":     "contradiction",
	}

	// Build entity -> detector type -> reflection IDs
	entityDetectors := make(map[string]map[string][]string)

	for _, reflID := range reflectionsCopy {
		for edgeType, detectorName := range detectorEdgeMap {
			targets, found := g.eng.VGetLinks(indexName, reflID, edgeType)
			if !found {
				continue
			}
			for _, entityID := range targets {
				if entityDetectors[entityID] == nil {
					entityDetectors[entityID] = make(map[string][]string)
				}
				entityDetectors[entityID][detectorName] = append(entityDetectors[entityID][detectorName], reflID)
			}
		}
	}

	// Create composite reflections for entities flagged by 2+ detector types
	for entityID, detectors := range entityDetectors {
		if len(detectors) < 2 {
			continue
		}

		var allReflectionIDs []string
		var confidences []float64
		var detectorNames []string

		for detName, reflIDs := range detectors {
			detectorNames = append(detectorNames, detName)
			for _, reflID := range reflIDs {
				allReflectionIDs = append(allReflectionIDs, reflID)
				if reflData, err := g.eng.VGet(indexName, reflID); err == nil {
					if c, ok := reflData.Metadata["confidence"].(float64); ok {
						confidences = append(confidences, c)
					}
				}
			}
		}

		// Geometric mean of confidences × diversity boost
		product := 1.0
		for _, c := range confidences {
			product *= c
		}
		geoMean := math.Pow(product, 1.0/float64(len(confidences)))
		diversityBoost := 0.7 + 0.3*math.Min(1.0, float64(len(detectors))/3.0)
		compositeConfidence := math.Min(1.0, geoMean*diversityBoost)

		slices.Sort(detectorNames)

		entityName := entityID
		if nodeData, err := g.eng.VGet(indexName, entityID); err == nil {
			if n, ok := nodeData.Metadata["name"].(string); ok && n != "" {
				entityName = n
			}
		}

		content := fmt.Sprintf("Cross-detector boost: '%s' flagged by %d detectors (%s). Composite confidence: %.2f.",
			entityName, len(detectors), strings.Join(detectorNames, ", "), compositeConfidence)

		reflectionID := fmt.Sprintf("reflection_cross_%d", time.Now().UnixNano())

		var vec []float32
		if nodeData, err := g.eng.VGet(indexName, entityID); err == nil {
			vec = nodeData.Vector
		}

		detectorAnys := make([]any, len(detectorNames))
		for i, d := range detectorNames {
			detectorAnys[i] = d
		}
		sourceAnys := make([]any, len(allReflectionIDs))
		for i, s := range allReflectionIDs {
			sourceAnys[i] = s
		}

		meta := map[string]any{
			"type":                 "reflection",
			"content":              content,
			"status":               "high_confidence",
			"confidence":           compositeConfidence,
			"detector_count":       float64(len(detectors)),
			"detector_types":       detectorAnys,
			"contributing_sources": sourceAnys,
			"_created_at":          float64(time.Now().Unix()),
		}

		if err := g.eng.VAdd(indexName, reflectionID, vec, meta); err != nil {
			slog.Warn("[Cognitive Engine] Failed to create cross-validation reflection", "error", err)
			continue
		}

		g.eng.VLink(indexName, reflectionID, entityID, "cross_validated", "cross_validated_by", 1.0, nil)
		for _, srcID := range allReflectionIDs {
			g.eng.VLink(indexName, reflectionID, srcID, "validates", "validated_by", 1.0, nil)
		}

		slog.Info("[Cognitive Engine] Cross-detector confidence boost!",
			"entity", entityName,
			"detectors", len(detectors),
			"confidence", compositeConfidence)
	}
}

// ============================================================================
// Epistemic Resolution (Fase 3): resolveVolatileBeliefs
// ============================================================================

// resolveVolatileBeliefs identifies reflections with low epistemic confidence
// and uses the LLM to consolidate conflicting memories into a single truth.
// This replaces the old autoResolveReflections with a mathematically rigorous approach.
func (g *Gardener) resolveVolatileBeliefs(indexName string) {
	// Fetch up to MaxPerCycle unresolved reflections (oldest first)
	maxProcess := g.cfg.EpistemicMaxPerCycle
	if maxProcess <= 0 {
		maxProcess = 3 // Default
	}

	refs, err := g.eng.VFilter(indexName, "type='reflection' AND status='unresolved'", maxProcess)
	if err != nil || len(refs) == 0 {
		return
	}

	// Sort by age (oldest first) - simple bubble sort for small N
	type refWithAge struct {
		id  string
		age float64
	}
	var refsWithAge []refWithAge
	now := float64(time.Now().Unix())

	for _, refID := range refs {
		refData, err := g.eng.VGet(indexName, refID)
		if err != nil {
			continue
		}
		createdAt := getMetadataFloat(refData.Metadata, "_created_at")
		refsWithAge = append(refsWithAge, refWithAge{id: refID, age: now - createdAt})
	}

	// Sort descending by age
	for i := 0; i < len(refsWithAge); i++ {
		for j := i + 1; j < len(refsWithAge); j++ {
			if refsWithAge[j].age > refsWithAge[i].age {
				refsWithAge[i], refsWithAge[j] = refsWithAge[j], refsWithAge[i]
			}
		}
	}

	// Process top N
	processCount := maxProcess
	if len(refsWithAge) < processCount {
		processCount = len(refsWithAge)
	}

	for i := 0; i < processCount; i++ {
		g.processEpistemicReflection(indexName, refsWithAge[i].id)
	}
}

// processEpistemicReflection handles a single reflection through the epistemic pipeline.
func (g *Gardener) processEpistemicReflection(indexName, reflectionID string) {
	// Verify reflection exists
	_, err := g.eng.VGet(indexName, reflectionID)
	if err != nil {
		return
	}

	// Get conflicting nodes via contradicts edges
	edges, found := g.eng.VGetEdges(indexName, reflectionID, "contradicts", 0)
	if !found || len(edges) < 2 {
		slog.Debug("[Gardener] Reflection has fewer than 2 conflicting nodes, skipping",
			"reflection", reflectionID, "nodes", len(edges))
		return
	}

	// Collect node data with dimension validation
	var nodesData []epistemicNodeInternal
	targetDim := 0

	for _, edge := range edges {
		nodeData, err := g.eng.VGet(indexName, edge.TargetID)
		if err != nil || len(nodeData.Vector) == 0 {
			continue
		}

		// Check dimensions match
		if targetDim == 0 {
			targetDim = len(nodeData.Vector)
		} else if len(nodeData.Vector) != targetDim {
			// Dimension mismatch - escalate to manual
			g.escalateToManual(indexName, reflectionID, "vector_dimension_mismatch")
			return
		}

		nodesData = append(nodesData, epistemicNodeInternal{
			id:       edge.TargetID,
			vector:   nodeData.Vector,
			metadata: nodeData.Metadata,
		})
	}

	if len(nodesData) < 2 {
		return
	}

	// Calculate centroid (mean of all vectors)
	centroid := make([]float32, targetDim)
	for _, node := range nodesData {
		for i := 0; i < targetDim; i++ {
			centroid[i] += node.vector[i]
		}
	}
	for i := 0; i < targetDim; i++ {
		centroid[i] /= float32(len(nodesData))
	}

	// Get epistemic config
	cfg := engine.DefaultEpistemicConfig()
	if g.cfg.EpistemicConfidenceThreshold > 0 {
		cfg.Thresholds.Volatile = g.cfg.EpistemicConfidenceThreshold
	}

	// Call VBeliefState
	state, err := g.eng.VBeliefState(indexName, centroid, 10, *cfg)
	if err != nil {
		slog.Warn("[Gardener] VBeliefState failed", "error", err, "reflection", reflectionID)
		return
	}

	// Check if volatile (below threshold)
	threshold := g.cfg.EpistemicConfidenceThreshold
	if threshold == 0 {
		threshold = 0.40
	}

	if state.Confidence >= threshold {
		slog.Info("[Gardener] Reflection not volatile, skipping",
			"reflection", reflectionID,
			"confidence", state.Confidence,
			"threshold", threshold)
		return
	}

	// It's volatile! Call LLM for resolution
	resolution, err := g.callEpistemicLLM(nodesData, state.Confidence)
	if err != nil {
		g.escalateToManual(indexName, reflectionID, "llm_error: "+err.Error())
		return
	}

	if !resolution.Resolvable {
		// Needs clarification
		g.eng.VSetMetadata(indexName, reflectionID, map[string]any{
			"status":                 "needs_clarification",
			"clarification_question": resolution.ClarificationQuestion,
			"epistemic_score":        state.Confidence,
			"_updated_at":            float64(time.Now().Unix()),
		})
		slog.Info("[Gardener] Reflection needs clarification",
			"reflection", reflectionID,
			"question", resolution.ClarificationQuestion)
		return
	}

	// Resolvable! Execute consolidation
	g.executeConsolidation(indexName, reflectionID, nodesData, resolution, centroid)
}

// epistemicNodeInternal is used for processing within the Gardener
type epistemicNodeInternal struct {
	id       string
	vector   []float32
	metadata map[string]any
}

// epistemicResolution represents the LLM response
type epistemicResolution struct {
	Resolvable            bool   `json:"resolvable"`
	ConsolidatedTruth     string `json:"consolidated_truth"`
	ClarificationQuestion string `json:"clarification_question"`
}

// callEpistemicLLM calls the LLM for epistemic resolution.
func (g *Gardener) callEpistemicLLM(nodes []epistemicNodeInternal, confidence float64) (*epistemicResolution, error) {
	if g.llm == nil {
		return nil, fmt.Errorf("LLM not available")
	}

	// Build prompt
	sysPrompt := `You are an epistemic resolution engine. Analyze conflicting memory statements and determine the consolidated truth based on temporal evidence and usage patterns.

Input: Array of facts with timestamps and access counts.
Resolution rules:
1. Newer facts generally supersede older ones
2. Higher access_count indicates more relevant information
3. If facts cannot be reconciled, ask for clarification
4. Provide a single, concise consolidated truth

Respond ONLY with valid JSON:
{
  "resolvable": true/false,
  "consolidated_truth": "The unified factual statement (1-2 sentences)",
  "clarification_question": "If not resolvable, what should be asked?"
}

Guidelines:
- resolvable=false only if truly contradictory with no temporal pattern
- consolidated_truth must synthesize all valid information
- clarification_question must be specific and actionable`

	userPrompt := fmt.Sprintf("Resolve these conflicting facts (epistemic confidence: %.2f/1.0):\n\n", confidence)
	for i, node := range nodes {
		content := getMetadataString(node.metadata, "content")
		createdAt := getMetadataFloat(node.metadata, "_created_at")
		accessCount := getMetadataInt(node.metadata, "_access_count")

		dateStr := time.Unix(int64(createdAt), 0).Format("2006-01-02")
		userPrompt += fmt.Sprintf("%d. \"%s\" (created: %s, accessed %d times)\n",
			i+1, content, dateStr, accessCount)
	}

	// Call LLM
	resp, err := g.llm.Chat(sysPrompt, userPrompt)
	if err != nil {
		return nil, err
	}

	// Parse JSON
	return g.parseEpistemicResponse(resp)
}

// parseEpistemicResponse extracts JSON from LLM response.
func (g *Gardener) parseEpistemicResponse(resp string) (*epistemicResolution, error) {
	// Try to find JSON block
	start := strings.Index(resp, "{")
	end := strings.LastIndex(resp, "}")

	if start == -1 || end == -1 || end <= start {
		return nil, fmt.Errorf("no JSON found in response")
	}

	jsonBlock := resp[start : end+1]

	var res epistemicResolution
	if err := json.Unmarshal([]byte(jsonBlock), &res); err != nil {
		return nil, fmt.Errorf("failed to parse JSON: %v", err)
	}

	return &res, nil
}

// executeConsolidation creates the master belief and VEvolve conflicting nodes.
func (g *Gardener) executeConsolidation(
	indexName, reflectionID string,
	nodes []epistemicNodeInternal,
	resolution *epistemicResolution,
	centroid []float32,
) {
	// Create master node
	masterID := fmt.Sprintf("belief_%d", time.Now().UnixNano())

	masterMeta := map[string]any{
		"content":            resolution.ConsolidatedTruth,
		"type":               "consolidated_belief",
		"_created_at":        float64(time.Now().Unix()),
		"_access_count":      0,
		"_consolidated_from": len(nodes),
		"source_reflection":  reflectionID,
	}

	if err := g.eng.VAdd(indexName, masterID, centroid, masterMeta); err != nil {
		g.escalateToManual(indexName, reflectionID, "vadd_master_failed: "+err.Error())
		return
	}

	// VEvolve each conflicting node to point to master
	successCount := 0
	for _, node := range nodes {
		// Create evolution metadata preserving original type
		evolveMeta := map[string]any{
			"content": node.metadata["content"],
			"type":    node.metadata["type"],
		}
		if evolveMeta["type"] == nil {
			evolveMeta["type"] = "memory"
		}

		_, err := g.eng.VEvolve(
			indexName,
			node.id,
			centroid, // Use centroid as the vector for the evolved truth
			evolveMeta,
			"Epistemic consolidation: "+resolution.ConsolidatedTruth,
		)
		if err != nil {
			slog.Warn("[Gardener] VEvolve failed", "node", node.id, "error", err)
			continue
		}
		successCount++
	}

	if successCount == 0 {
		// All VEvolve failed - master is orphaned
		g.escalateToManual(indexName, reflectionID, "all_vevolve_failed")
		return
	}

	// Update reflection to resolved
	g.eng.VSetMetadata(indexName, reflectionID, map[string]any{
		"status":              "resolved",
		"resolution":          "epistemic_consolidation",
		"consolidated_belief": masterID,
		"nodes_consolidated":  successCount,
		"_updated_at":         float64(time.Now().Unix()),
	})

	slog.Info("[Gardener] Successfully consolidated belief",
		"reflection", reflectionID,
		"master", masterID,
		"nodes_consolidated", successCount,
		"truth", resolution.ConsolidatedTruth)
}

// escalateToManual marks a reflection for human review.
func (g *Gardener) escalateToManual(indexName, reflectionID, reason string) {
	g.eng.VSetMetadata(indexName, reflectionID, map[string]any{
		"status":       "needs_manual_review",
		"error_reason": reason,
		"_updated_at":  float64(time.Now().Unix()),
	})
	slog.Warn("[Gardener] Escalated to manual review",
		"reflection", reflectionID,
		"reason", reason)
}

// Helper functions
func getMetadataString(m map[string]any, key string) string {
	if v, ok := m[key].(string); ok {
		return v
	}
	return ""
}

func getMetadataFloat(m map[string]any, key string) float64 {
	if m == nil {
		return 0
	}
	val, ok := m[key]
	if !ok {
		return 0
	}
	switch v := val.(type) {
	case float64:
		return v
	case float32:
		return float64(v)
	case int:
		return float64(v)
	case int64:
		return float64(v)
	default:
		return 0
	}
}

func getMetadataInt(m map[string]any, key string) int {
	if m == nil {
		return 0
	}
	val, ok := m[key]
	if !ok {
		return 0
	}
	switch v := val.(type) {
	case int:
		return v
	case int64:
		return int(v)
	case float64:
		return int(v)
	case float32:
		return int(v)
	default:
		return 0
	}
}

// ============================================================================
// RFC 001: Core Fact Extraction ("The Gardener")
// ============================================================================

// coreFactExtractionPrompt is the LLM prompt for extracting immutable facts.
const coreFactExtractionPrompt = `Analyze the following user interactions. Extract ONLY static, long-lasting facts about the user (e.g., name, profession, pets, strict preferences, constraints, skills, languages known, location).

IMPORTANT: Ignore temporary states, feelings, or daily events. Do not infer facts that are not explicitly stated or strongly implied.

Input format: JSON array of interaction objects with "id" and "content" fields.
Output format: JSON array of extracted facts as strings. Each fact should be self-contained and atomic.

Example:
Input: [{"id": "1", "content": "Mi chiamo Marco e lavoro come ingegnere"}, {"id": "2", "content": "Ho un cane di nome Fido"}]
Output: ["User name is Marco", "User profession is engineer", "User has a dog named Fido"]

Rules:
1. Facts must be immutable or long-lasting (valid for months/years)
2. Use clear, concise language
3. Include negations if explicitly stated (e.g., "User does not eat meat")
4. If uncertain, do not include the fact
5. Return empty array [] if no facts can be extracted`

// coreFactExtractionResponse is the LLM response structure.
type coreFactExtractionResponse struct {
	Facts []string `json:"facts"`
}

// detectCoreFacts analyzes recent user interactions to extract immutable facts.
// It creates core_fact nodes that are pinned (no time-decay) and linked to source memories.
func (g *Gardener) detectCoreFacts(indexName string) {
	// 1. Fetch recent user_interaction or episodic nodes
	filter := "(type='user_interaction' OR memory_layer='episodic') AND _archived!=true"
	candidateIDs, err := g.eng.VFilter(indexName, filter, 50)
	if err != nil || len(candidateIDs) == 0 {
		return
	}

	// 2. Fetch full data
	candidates, err := g.eng.VGetMany(indexName, candidateIDs)
	if err != nil || len(candidates) == 0 {
		return
	}

	// 3. Filter out those already processed (check for existing extracted_from links)
	var toProcess []core.VectorData
	for _, cand := range candidates {
		// Check if already linked from a core_fact
		incoming, found := g.eng.VGetIncoming(indexName, cand.ID, "extracted_from")
		if !found || len(incoming) == 0 {
			toProcess = append(toProcess, cand)
		}
	}

	if len(toProcess) == 0 {
		return
	}

	// 4. Group by user_id if available, or process individually
	userGroups := make(map[string][]core.VectorData)
	ungrouped := []core.VectorData{}

	for _, item := range toProcess {
		if userID, ok := item.Metadata["user_id"].(string); ok && userID != "" {
			userGroups[userID] = append(userGroups[userID], item)
		} else {
			ungrouped = append(ungrouped, item)
		}
	}

	// 5. Process each group
	minConfidence := g.cfg.CoreFactMinConfidence
	if minConfidence == 0 {
		minConfidence = 0.85
	}

	for userID, items := range userGroups {
		g.processCoreFactExtraction(indexName, userID, items, minConfidence)
	}

	// 6. Process ungrouped items individually
	for _, item := range ungrouped {
		g.processCoreFactExtraction(indexName, "", []core.VectorData{item}, minConfidence)
	}
}

// processCoreFactExtraction sends items to LLM and creates core_fact nodes.
func (g *Gardener) processCoreFactExtraction(indexName, userID string, items []core.VectorData, minConfidence float64) {
	if len(items) == 0 {
		return
	}

	// Prepare input for LLM
	type interactionInput struct {
		ID      string `json:"id"`
		Content string `json:"content"`
	}

	var inputs []interactionInput
	for _, item := range items {
		content := ""
		if c, ok := item.Metadata["content"].(string); ok {
			content = c
		}
		if content == "" {
			// Try other common text fields
			for _, field := range []string{"text", "summary", "description"} {
				if c, ok := item.Metadata[field].(string); ok && c != "" {
					content = c
					break
				}
			}
		}
		if content != "" {
			inputs = append(inputs, interactionInput{ID: item.ID, Content: content})
		}
	}

	if len(inputs) == 0 {
		return
	}

	inputJSON, _ := json.Marshal(inputs)

	// Call LLM
	userPrompt := string(inputJSON)
	slog.Info("[Cognitive Engine] Extracting core facts", "user", userID, "interactions", len(inputs))

	response, err := g.llm.Chat(coreFactExtractionPrompt, userPrompt)
	if err != nil || response == "" {
		slog.Warn("[Cognitive Engine] Core fact extraction failed", "error", err)
		return
	}

	// Clean response
	response = strings.TrimSpace(strings.TrimPrefix(strings.TrimSuffix(response, "```"), "```"))
	if strings.HasPrefix(response, "json") {
		response = strings.TrimPrefix(response, "json")
		response = strings.TrimSpace(response)
	}

	// Parse response
	var extraction coreFactExtractionResponse
	if err := json.Unmarshal([]byte(response), &extraction); err != nil {
		// Try parsing as raw string array
		var rawFacts []string
		if err := json.Unmarshal([]byte(response), &rawFacts); err != nil {
			slog.Warn("[Cognitive Engine] Failed to parse core facts", "error", err)
			return
		}
		extraction.Facts = rawFacts
	}

	if len(extraction.Facts) == 0 {
		slog.Debug("[Cognitive Engine] No core facts extracted", "user", userID)
		return
	}

	// Create core_fact nodes for each extracted fact
	for _, fact := range extraction.Facts {
		fact = strings.TrimSpace(fact)
		if fact == "" {
			continue
		}

		// Generate deterministic ID based on content hash
		factID := fmt.Sprintf("core_fact_%d", time.Now().UnixNano())

		meta := map[string]any{
			"type":         "core_fact",
			"content":      fact,
			"_pinned":      true, // No time-decay
			"confidence":   minConfidence,
			"extracted_at": float64(time.Now().Unix()),
			"_created_at":  float64(time.Now().Unix()),
		}

		if userID != "" {
			meta["user_id"] = userID
		}

		// Use zero vector (will be embedded if needed on first access)
		var zeroVec []float32

		err := g.eng.VAdd(indexName, factID, zeroVec, meta)
		if err != nil {
			slog.Warn("[Cognitive Engine] Failed to create core_fact node", "error", err)
			continue
		}

		// Link to source memories
		for _, item := range items {
			g.eng.VLink(indexName, factID, item.ID, "extracted_from", "", 1.0, nil)
		}

		g.reflectionsMu.Lock()
		g.newReflections = append(g.newReflections, factID)
		g.reflectionsMu.Unlock()

		slog.Info("[Cognitive Engine] Core fact extracted",
			"id", factID,
			"user", userID,
			"fact", fact[:min(len(fact), 50)]+"...")
	}
}

// min returns the minimum of two integers.
func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}
